course('javascript', 'JavaScript', 'fab fa-js', '#F7DF1E', [
  { name: 'Core Concepts', concepts: [
    c('Closures', 'Intermediate', 'Function bundled with its lexical environment, retaining access to outer scope variables', { codeExample: 'function createCounter() {\n  let count = 0;\n  return function() {\n    count++;\n    return count;\n  };\n}\nconst counter = createCounter();\nconsole.log(counter()); // 1\nconsole.log(counter()); // 2', keyPoints: ['Inner function remembers outer scope', 'Common in module patterns', 'Used in event handlers and callbacks', 'Enables data privacy'], commonMistakes: ['Creating closures in loops without IIFE', 'Memory leaks with large closures'] }),
    c('Hoisting', 'Intermediate', 'Variable and function declarations are moved to the top of their scope during compilation', { codeExample: 'console.log(x); // undefined (not error)\nvar x = 5;\n\nfoo(); // works - function hoisted\nfunction foo() { return "bar"; }\n\nbar(); // TypeError - not hoisted\nvar bar = function() { return "baz"; }', keyPoints: ['var hoisted, not initialized', 'let/const hoisted but in TDZ', 'Function declarations fully hoisted', 'Function expressions not hoisted'] }),
    c('this Keyword', 'Intermediate', 'Context-dependent keyword that refers to the execution context of a function', { codeExample: 'const obj = {\n  name: "Alice",\n  greet() { console.log(this.name); },\n  arrow: () => console.log(this.name)\n};\nobj.greet(); // Alice\nobj.arrow(); // undefined (lexical this)\n\nfunction Person(name) {\n  this.name = name;\n}\nconst p = new Person("Bob");\nconsole.log(p.name); // Bob', keyPoints: ['this depends on how function is called', 'Arrow functions have lexical this', 'bind, call, apply explicitly set this'] }),
    c('Prototypes & Inheritance', 'Advanced', 'JavaScript uses prototypal inheritance where objects inherit from other objects via prototype chain', { codeExample: 'function Animal(name) {\n  this.name = name;\n}\nAnimal.prototype.speak = function() {\n  return this.name + " makes a sound";\n};\n\nfunction Dog(name) {\n  Animal.call(this, name);\n}\nDog.prototype = Object.create(Animal.prototype);\n\nconst dog = new Dog("Rex");\nconsole.log(dog.speak()); // Rex makes a sound', keyPoints: ['Every object has a prototype', 'Prototype chain for property lookup', 'class is syntactic sugar over prototypes'], commonMistakes: ['Confusing __proto__ and prototype'] }),
    c('Type Coercion', 'Beginner', 'Automatic or implicit conversion of values from one type to another during operations', { codeExample: 'console.log(1 + "2"); // "12"\nconsole.log("5" - 3); // 2\nconsole.log(0 == false); // true (loose)\nconsole.log(0 === false); // false (strict)\nconsole.log([] == false); // true', keyPoints: ['== allows coercion, === does not', 'String concat coerces to string', 'Arithmetic coerces to number', 'Prefer === over =='] }),
    c('Strict Mode', 'Beginner', '"use strict" enables stricter parsing and error handling', { codeExample: '"use strict";\n// x = 10; // ReferenceError\n// delete Object.prototype; // TypeError\n\nfunction strictFunc() {\n  "use strict";\n  // this is undefined in function calls\n}', keyPoints: ['Prevents accidental globals', 'Makes this undefined in non-methods', 'Throws on duplicate params'] }),
    c('typeof vs instanceof', 'Beginner', 'typeof returns type as string; instanceof checks prototype chain', { codeExample: 'console.log(typeof "hello"); // "string"\nconsole.log(typeof 42); // "number"\nconsole.log(typeof null); // "object" (bug!)\nconsole.log([] instanceof Array); // true\nconsole.log({} instanceof Object); // true', keyPoints: ['typeof for primitives', 'instanceof for object types', 'typeof null === "object" (bug)', 'Array.isArray() for arrays'] }),
  ]},
  { name: 'DOM & Browser APIs', concepts: [
    c('DOM Manipulation', 'Intermediate', 'Interacting with the Document Object Model to dynamically change page content', { codeExample: 'const div = document.createElement("div");\ndiv.textContent = "Hello";\ndiv.classList.add("highlight");\ndocument.body.appendChild(div);\n\nconst el = document.querySelector(".my-class");\nconst all = document.querySelectorAll("li");\n\nel.addEventListener("click", (e) => {\n  console.log("Clicked!", e.target);\n});', keyPoints: ['createElement, appendChild', 'querySelector / querySelectorAll', 'classList for class manipulation', 'Event delegation with bubbling'] }),
    c('Event Propagation', 'Intermediate', 'Three phases: capturing, target, bubbling of event flow through DOM tree', { codeExample: 'parent.addEventListener("click", () => {\n  console.log("Parent capturing");\n}, true); // capture\n\nchild.addEventListener("click", (e) => {\n  console.log("Child bubbling");\n  e.stopPropagation();\n}); // bubbling (default)', keyPoints: ['Capturing (root to target)', 'Target phase', 'Bubbling (target to root)', 'stopPropagation vs stopImmediatePropagation'] }),
    c('LocalStorage & SessionStorage', 'Beginner', 'Web Storage API for persisting key-value data on the client side', { codeExample: 'localStorage.setItem("theme", "dark");\nconst theme = localStorage.getItem("theme");\nlocalStorage.removeItem("theme");\n\nsessionStorage.setItem("temp", "data");\n\nlocalStorage.setItem("user", JSON.stringify({id: 1, name: "Alice"}));\nconst user = JSON.parse(localStorage.getItem("user"));', keyPoints: ['5-10MB storage limit', 'localStorage persists, sessionStorage per-tab', 'Strings only (JSON.stringify/parse)'] }),
    c('Fetch API', 'Intermediate', 'Modern interface for making HTTP requests, replacing XMLHttpRequest', { codeExample: 'async function getUser(id) {\n  try {\n    const response = await fetch(`/api/users/${id}`);\n    if (!response.ok) {\n      throw new Error(`HTTP ${response.status}`);\n    }\n    return await response.json();\n  } catch (error) {\n    console.error("Fetch failed:", error);\n    throw error;\n  }\n}', keyPoints: ['Promise-based API', 'response.ok for status checking', 'response.json() returns promise', 'AbortController for cancellation'] }),
    c('Web Workers', 'Advanced', 'Running scripts in background threads separate from the main UI thread', { codeExample: '// main.js\nconst worker = new Worker("worker.js");\nworker.postMessage({ data: heavyData });\nworker.onmessage = (e) => {\n  console.log("Result:", e.data);\n};\n\n// worker.js\nself.onmessage = (e) => {\n  const result = performHeavyComputation(e.data);\n  self.postMessage(result);\n};', keyPoints: ['No DOM access in workers', 'Message-based communication', 'Service workers for offline/caching'] }),
    c('Intersection Observer', 'Intermediate', 'Efficiently detecting element visibility relative to viewport', { codeExample: 'const observer = new IntersectionObserver((entries) => {\n  entries.forEach(entry => {\n    if (entry.isIntersecting) {\n      console.log("Visible:", entry.target);\n      entry.target.src = entry.target.dataset.src;\n      observer.unobserve(entry.target);\n    }\n  });\n}, { threshold: 0.5 });\n\ndocument.querySelectorAll(".lazy").forEach(el => observer.observe(el));', keyPoints: ['Better than scroll event listeners', 'threshold, rootMargin options', 'Lazy loading images', 'Infinite scroll'] }),
  ]},
  { name: 'Async JavaScript', concepts: [
    c('Event Loop', 'Advanced', 'Mechanism that handles asynchronous callbacks in single-threaded JavaScript runtime', { codeExample: 'console.log("1");\nsetTimeout(() => console.log("2"), 0);\nPromise.resolve().then(() => console.log("3"));\nconsole.log("4");\n// Output: 1, 4, 3, 2', keyPoints: ['Call stack, microtask queue, macrotask queue', 'Promises go to microtask queue', 'setTimeout goes to macrotask queue', 'Microtasks before next macrotask'] }),
    c('Callbacks', 'Beginner', 'Functions passed as arguments to other functions, executed after async operations complete', { codeExample: 'function fetchData(callback) {\n  setTimeout(() => {\n    const data = { id: 1 };\n    callback(null, data);\n  }, 1000);\n}\n\nfetchData((err, data) => {\n  if (err) {\n    console.error("Error:", err);\n    return;\n  }\n  console.log("Data:", data);\n});', keyPoints: ['Error-first callback convention', 'Callback hell with nesting', 'Replaced by Promises/async-await'] }),
    c('Promises', 'Intermediate', 'Objects representing the eventual completion or failure of an async operation', { codeExample: 'function fetchUser(id) {\n  return new Promise((resolve, reject) => {\n    setTimeout(() => {\n      if (id > 0) {\n        resolve({ id, name: "Alice" });\n      } else {\n        reject(new Error("Invalid ID"));\n      }\n    }, 1000);\n  });\n}\n\nfetchUser(1)\n  .then(user => console.log(user))\n  .catch(err => console.error(err))\n  .finally(() => console.log("Done"));', keyPoints: ['States: pending, fulfilled, rejected', 'Chaining with .then()', 'Error handling with .catch()', 'Promise.all, Promise.race'] }),
    c('async/await', 'Intermediate', 'Syntactic sugar over Promises providing synchronous-looking async code', { codeExample: 'async function processUsers() {\n  try {\n    const user = await fetchUser(1);\n    const posts = await fetchPosts(user.id);\n    return { user, posts };\n  } catch (error) {\n    console.error("Failed:", error);\n    throw error;\n  }\n}\n\nasync function getMultiple() {\n  const [u1, u2] = await Promise.all([\n    fetchUser(1), fetchUser(2)\n  ]);\n  return [u1, u2];\n}', keyPoints: ['await pauses async function', 'Error handling with try/catch', 'Promise.all for parallel execution'] }),
    c('Error Handling Patterns', 'Intermediate', 'Strategies for robust error handling in sync and async code', { codeExample: 'function divide(a, b) {\n  if (b === 0) throw new Error("Division by zero");\n  return a / b;\n}\n\nasync function safeFetch(url) {\n  try {\n    const res = await fetch(url);\n    if (!res.ok) throw new Error(`HTTP ${res.status}`);\n    return await res.json();\n  } catch (err) {\n    console.error(err.message);\n    return null;\n  }\n}\n\nwindow.addEventListener("unhandledrejection", (e) => {\n  console.error("Unhandled rejection:", e.reason);\n});', keyPoints: ['try/catch for sync errors', '.catch() or try/catch for async', 'Global error handlers', 'Meaningful error messages'] }),
  ]},
  { name: "ES6+ Features", concepts: [
    c('let, const & Block Scope', 'Beginner', 'let and const provide block-level scoping versus var function-level scoping', { codeExample: '{\n  var a = 1;\n  let b = 2;\n  const c = 3;\n}\nconsole.log(a); // 1 (var leaks)\n// console.log(b); // ReferenceError\n\nconst obj = { name: "Alice" };\nobj.name = "Bob"; // OK\n// obj = {}; // TypeError', keyPoints: ['let allows reassignment, const does not', 'Block-scoped', 'Temporal Dead Zone', 'const objects modifiable'] }),
    c('Destructuring', 'Beginner', 'Unpack values from arrays or properties from objects into distinct variables', { codeExample: 'const [a, b, ...rest] = [1, 2, 3, 4, 5];\nconst { name, age, ...details } = user;\nconst { city = "Unknown" } = user;\nconst { name: userName } = user;\n\nfunction printUser({ name, age }) {\n  console.log(`${name} is ${age}`);\n}', keyPoints: ['Works with arrays and objects', 'Default values', 'Rest operator (...) collects remaining', 'Nested destructuring'] }),
    c('Spread & Rest Operators', 'Beginner', '... operator spreads elements or collects remaining items depending on context', { codeExample: 'const arr2 = [...[1, 2, 3], 4, 5];\nconst obj2 = { ...{a: 1, b: 2}, c: 3 };\n\nfunction sum(...numbers) {\n  return numbers.reduce((a, b) => a + b, 0);\n}\n\nconst [first, ...rest] = [1, 2, 3, 4];', keyPoints: ['Spread unpacks iterables/objects', 'Rest collects remaining', 'Object spread for shallow merge'] }),
    c('Arrow Functions', 'Beginner', 'Concise function syntax with lexical this binding', { codeExample: 'const double = (x) => x * 2;\nconst add = (a, b) => a + b;\n\nfunction Timer() {\n  this.seconds = 0;\n  setInterval(() => {\n    this.seconds++; // lexical this\n  }, 1000);\n}', keyPoints: ['Shorter syntax', 'Lexical this binding', 'Implicit return for single expression', 'Cannot be used as constructors'] }),
    c('Template Literals', 'Beginner', 'String literals with embedded expressions and multi-line support using backticks', { codeExample: 'const name = "Alice";\nconst age = 30;\nconst msg = `Hello ${name}, you are ${age} years old`;\n\nconst html = `\n  <div>\n    <h1>${name}</h1>\n  </div>\n`;\n\nfunction highlight(strings, ...values) {\n  return strings.reduce((r, s, i) => `${r}${s}<strong>${values[i]||""}</strong>`, "");\n}', keyPoints: ['Backtick delimiters', '${} interpolation', 'Multi-line support', 'Tagged templates'] }),
    c('Modules (import/export)', 'Intermediate', 'ES6 module system for organizing code into separate files with explicit dependencies', { codeExample: '// math.js\nexport function add(a, b) { return a + b; }\nexport const PI = 3.14159;\nexport default class Calculator { }\n\n// app.js\nimport Calculator, { add, PI as pi } from "./math.js";\nimport * as math from "./math.js";\n\nconst module = await import("./math.js");', keyPoints: ['Named exports vs default export', 'Import destructuring', 'Dynamic import() returns Promise', 'Tree shaking via static analysis'] }),
  ]},
  { name: 'Advanced JavaScript', concepts: [
    c('Currying', 'Advanced', 'Transforming a function with multiple arguments into a sequence of functions each taking one argument', { codeExample: 'function curry(fn) {\n  return function curried(...args) {\n    if (args.length >= fn.length) {\n      return fn.apply(this, args);\n    }\n    return (...more) => curried(...args, ...more);\n  };\n}\n\nfunction add(a, b, c) { return a + b + c; }\nconst curriedAdd = curry(add);\nconsole.log(curriedAdd(1)(2)(3)); // 6\n\nconst log = (prefix) => (message) => `${prefix}: ${message}`;\nconst info = log("INFO");\nconsole.log(info("Server started"));', keyPoints: ['Transforms multi-arg to nested unary', 'Enables partial application', 'Useful for function composition'] }),
    c('Memoization', 'Intermediate', 'Caching function results based on input arguments to avoid redundant computation', { codeExample: 'function memoize(fn) {\n  const cache = new Map();\n  return (...args) => {\n    const key = JSON.stringify(args);\n    if (cache.has(key)) {\n      console.log("Cache hit:", key);\n      return cache.get(key);\n    }\n    const result = fn(...args);\n    cache.set(key, result);\n    return result;\n  };\n}\n\nconst factorial = memoize((n) => {\n  if (n <= 1) return 1;\n  return n * factorial(n - 1);\n});', keyPoints: ['Cache key based on arguments', 'Pure functions work best', 'Memory vs computation trade-off'] }),
    c('Proxy & Reflect', 'Advanced', 'Intercepting and customizing operations on objects using Proxy traps and Reflect', { codeExample: 'const handler = {\n  get(target, prop, receiver) {\n    if (prop in target) {\n      console.log(`GET ${String(prop)}: ${target[prop]}`);\n      return Reflect.get(target, prop, receiver);\n    }\n    return "Property not found";\n  },\n  set(target, prop, value) {\n    console.log(`SET ${String(prop)} = ${value}`);\n    return Reflect.set(target, prop, value);\n  }\n};\n\nconst obj = new Proxy({ name: "Alice" }, handler);', keyPoints: ['Traps: get, set, has, deleteProperty', 'Reflect API mirrors Proxy traps', 'Used for validation, logging, reactivity'] }),
    c('Symbols & Iterators', 'Intermediate', 'Unique primitive values used as property keys and iteration protocol', { codeExample: 'const uniqueId = Symbol("id");\nconst obj = { [uniqueId]: 123 };\n\nclass Range {\n  constructor(start, end) {\n    this.start = start;\n    this.end = end;\n  }\n\n  [Symbol.iterator]() {\n    let current = this.start;\n    return {\n      next: () => ({ value: current, done: current++ > this.end })\n    };\n  }\n}\n\nfor (const n of new Range(1, 5)) {\n  console.log(n); // 1,2,3,4,5\n}', keyPoints: ['Symbols are always unique', 'Used as private-like keys', 'Symbol.iterator for custom iteration'] }),
    c('Generators & Iterators', 'Advanced', 'Functions using function* and yield that can pause/resume execution', { codeExample: 'function* fibonacci() {\n  let a = 0, b = 1;\n  while (true) {\n    yield a;\n    [a, b] = [b, a + b];\n  }\n}\n\nconst fib = fibonacci();\nfor (let i = 0; i < 10; i++) {\n  console.log(fib.next().value);\n}\n\nasync function* asyncGenerator() {\n  yield await fetchData(1);\n  yield await fetchData(2);\n}\n\nfor await (const data of asyncGenerator()) {\n  console.log(data);\n}', keyPoints: ['function* declares generator', 'yield pauses and produces value', 'async generators'], followUps: ['How do generators differ from async/await?'] }),
    c('WebSocket & SSE', 'Intermediate', 'Real-time communication: WebSocket (bidirectional) and Server-Sent Events', { codeExample: 'const ws = new WebSocket("wss://example.com");\nws.onopen = () => ws.send("Hello server");\nws.onmessage = (e) => console.log("Received:", e.data);\nws.onclose = () => console.log("Disconnected");\n\nconst evtSource = new EventSource("/api/events");\nevtSource.onmessage = (e) => {\n  console.log("Event:", e.data);\n};', keyPoints: ['WebSocket: full-duplex persistent', 'SSE: server push one-way', 'EventSource API for SSE'] }),
    c('Service Workers', 'Advanced', 'Scripts running in background enabling offline support, caching, push notifications', { codeExample: '// service-worker.js\nself.addEventListener("install", (event) => {\n  event.waitUntil(\n    caches.open("v1").then((cache) => {\n      return cache.addAll(["/", "/styles.css", "/app.js"]);\n    })\n  );\n});\n\nself.addEventListener("fetch", (event) => {\n  event.respondWith(\n    caches.match(event.request).then((response) => {\n      return response || fetch(event.request);\n    })\n  );\n});\n\nnavigator.serviceWorker.register("/service-worker.js");', keyPoints: ['Network proxy between browser and server', 'Cache API for responses', 'Lifecycle: install, activate, fetch'] }),
  ]},
  { name: 'Node.js Basics', concepts: [
    c('Event-Driven Architecture', 'Intermediate', "Node.js uses an event-driven, non-blocking I/O model built on the event loop", { codeExample: 'const EventEmitter = require("events");\nclass OrderSystem extends EventEmitter {}\nconst orders = new OrderSystem();\n\norders.on("order", (item) => {\n  console.log(`Processing: ${item}`);\n});\n\norders.emit("order", "Pizza");', keyPoints: ['Event loop processes callbacks', 'EventEmitter for custom events', 'Streams for large data'] }),
    c('Buffers & Streams', 'Intermediate', 'Buffers handle binary data; Streams process data chunk by chunk', { codeExample: 'const buf = Buffer.from("Hello");\nconsole.log(buf.toString()); // Hello\n\nconst fs = require("fs");\nconst readStream = fs.createReadStream("large.txt", "utf8");\nreadStream.on("data", (chunk) => {\n  console.log("Received chunk:", chunk.length);\n});\n\nconst { Transform } = require("stream");\nconst upper = new Transform({\n  transform(chunk, encoding, callback) {\n    this.push(chunk.toString().toUpperCase());\n    callback();\n  }\n});', keyPoints: ['Buffer for binary data', 'Readable, Writable, Transform, Duplex', 'Backpressure handling', '.pipe() method'] }),
    c('File System Module', 'Intermediate', 'fs module for file system interaction with sync, callback, and promise APIs', { codeExample: 'const fs = require("fs/promises");\n\nasync function fileOps() {\n  const data = await fs.readFile("file.txt", "utf8");\n  await fs.writeFile("output.txt", data.toUpperCase());\n  await fs.appendFile("log.txt", "New entry\\n");\n  const files = await fs.readdir("./");\n  console.log(files);\n  const stats = await fs.stat("file.txt");\n  console.log(stats.size);\n}', keyPoints: ['fs/promises for async/await', 'fs.existsSync to check', 'fs.watch for file watching', 'Path module'] }),
    c('NPM & Package Management', 'Beginner', 'Node Package Manager for installing, managing, and publishing packages', { codeExample: '# Install\nnpm install express\nnpm install --save-dev jest\n\n# package.json scripts\n# "scripts": {\n#   "start": "node server.js",\n#   "test": "jest"\n# }\n\n# Semantic versioning\n# ^1.2.3 (compatible with 1.x.x)\n# ~1.2.3 (compatible with 1.2.x)', keyPoints: ['package.json defines metadata', 'node_modules contains packages', 'package-lock.json locks versions', 'Semantic versioning'] }),
    c('Middleware Pattern', 'Intermediate', 'Pipeline of functions that process HTTP requests in order', { codeExample: 'const express = require("express");\nconst app = express();\n\napp.use(express.json());\n\n// Logger middleware\napp.use((req, res, next) => {\n  console.log(`${req.method} ${req.path}`);\n  next();\n});\n\n// Route\napp.get("/api/users", async (req, res) => {\n  try {\n    const users = await db.findMany();\n    res.json(users);\n  } catch (err) {\n    next(err);\n  }\n});\n\n// Error handler\napp.use((err, req, res, next) => {\n  res.status(500).json({ error: err.message });\n});', keyPoints: ['Middleware pipeline', 'Error handler with 4 params', 'next() passes control', 'Order matters'] }),
  ]},
]);
// ========== JAVA (50 concepts) ==========
course('java', 'Java', 'fab fa-java', '#ED8B00', [
  { name: 'Core Java', concepts: [
    c('JVM Architecture', 'Advanced', 'Java Virtual Machine that executes bytecode, providing platform independence', { keyPoints: ['ClassLoader, Runtime Data Areas, Execution Engine', 'Stack stores frames, Heap stores objects', 'GC runs on Heap', 'JIT compilation for performance'] }),
    c('Garbage Collection', 'Advanced', 'Automatic memory management that reclaims heap memory from unreachable objects', { codeExample: '// System.gc() is just a suggestion\n// Generational: Young -> Old -> Metaspace\n// Collectors: G1, ZGC, Shenandoah\nSystem.gc(); // Not guaranteed', keyPoints: ['Generational collection', 'Stop-the-world events', 'GC tuning with JVM flags', 'G1GC default since Java 9'], followUps: ['How does G1GC work?', 'Minor vs Full GC?'] }),
    c('OOP Concepts', 'Beginner', 'Four pillars: Encapsulation, Inheritance, Polymorphism, Abstraction', { codeExample: 'abstract class Animal {\n    abstract void sound();\n}\nclass Dog extends Animal {\n    @Override\n    void sound() { System.out.println("Bark"); }\n}\nAnimal a = new Dog();\na.sound(); // Runtime polymorphism', keyPoints: ['Encapsulation: private + getters/setters', 'Inheritance: extends', 'Polymorphism: overloading (compile) / overriding (runtime)', 'Abstraction: abstract classes, interfaces'] }),
    c('Access Modifiers', 'Beginner', 'Controlling visibility: private, default, protected, public', { codeExample: 'public class Example {\n    private int secret = 1;       // same class\n    int defaultValue = 2;         // package\n    protected int inherited = 3;  // package + subclasses\n    public int open = 4;          // everywhere\n}', keyPoints: ['private: class only', 'default (package): no modifier', 'protected: package + subclasses', 'public: everywhere'] }),
    c('Static Keyword', 'Beginner', 'Static members belong to the class itself rather than instances', { codeExample: 'public class Config {\n    public static String APP_NAME = "MyApp";\n    private static int counter = 0;\n\n    public static int increment() { return ++counter; }\n\n    static {\n        System.out.println("Config loaded");\n    }\n}', keyPoints: ['Static fields shared across instances', 'Static methods cannot access instance fields', 'Static blocks for class initialization'] }),
    c('String Pool & Immutability', 'Intermediate', 'Strings are immutable, cached in the string pool for memory efficiency', { codeExample: 'String a = "hello";\nString b = "hello";\nString c = new String("hello");\n\nSystem.out.println(a == b);       // true (pool)\nSystem.out.println(a == c);       // false (new object)\nSystem.out.println(a.equals(c));  // true (content)\n\nStringBuilder sb = new StringBuilder("hello");\nsb.append(" world");', keyPoints: ['String interning for literals', 'new String() creates new object', 'StringBuilder/StringBuffer for mutable strings'] }),
    c('Wrapper Classes & Autoboxing', 'Intermediate', 'Object wrappers for primitives with automatic conversion', { codeExample: 'Integer x = 10;  // autoboxing\nint y = x;        // unboxing\n\nInteger a = 127;\nInteger b = 127;\nSystem.out.println(a == b); // true (cached)\n\nInteger c = 200;\nInteger d = 200;\nSystem.out.println(c == d); // false (not cached)', keyPoints: ['Primitive to wrapper: autoboxing', 'Cache range -128 to 127', 'Use .equals() not == for wrappers'] }),
  ]},
  { name: 'Collections Framework', concepts: [
    c('HashMap Internals', 'Advanced', 'Hash-based Map using buckets of linked lists or trees for collision resolution', { codeExample: 'Map<String, Integer> map = new HashMap<>();\nmap.put("one", 1);\n// Uses hashCode() for bucket\n// Uses equals() for exact key\n// Collision: LinkedList -> Tree (if 8+)\n\nfor (Map.Entry<String, Integer> e : map.entrySet()) {\n    System.out.println(e.getKey() + ": " + e.getValue());\n}', keyPoints: ['Initial capacity 16, load factor 0.75', 'Separate chaining for collisions', 'TREEIFY_THRESHOLD = 8', 'O(1) avg, O(log n) worst'] }),
    c('ArrayList vs LinkedList', 'Intermediate', 'Array-based vs node-based list implementations', { codeExample: 'List<String> al = new ArrayList<>();\nal.add("a");  // O(1) amortized\nal.get(0);    // O(1)\nal.remove(0); // O(n)\n\nList<String> ll = new LinkedList<>();\nll.add("a");  // O(1)\nll.get(0);    // O(n)\nll.remove(0); // O(1) with pointer', compareWith: 'ArrayList', keyPoints: ['ArrayList: fast random access', 'LinkedList: fast insert/delete at ends', 'ArrayList uses less memory'] }),
    c('ConcurrentHashMap', 'Advanced', 'Thread-safe HashMap using lock striping for better concurrency', { codeExample: 'ConcurrentHashMap<String, Integer> map = new ConcurrentHashMap<>();\nmap.put("key", 1);\nmap.putIfAbsent("key", 2); // atomic\n\nmap.compute("counter", (k, v) -> v == null ? 1 : v + 1);', keyPoints: ['Lock striping (multiple locks)', 'No ConcurrentModificationException', 'computeIfAbsent for atomic ops'] }),
    c('TreeMap & TreeSet', 'Intermediate', 'Red-Black tree based sorted collections with O(log n) operations', { codeExample: 'TreeMap<String, Integer> map = new TreeMap<>();\nmap.put("banana", 2);\nmap.put("apple", 1);\nmap.put("cherry", 3);\n\n// Sorted by key\nfor (Map.Entry<String, Integer> e : map.entrySet()) {\n    System.out.println(e.getKey() + ": " + e.getValue());\n}\n// apple:1, banana:2, cherry:3\n\nSystem.out.println(map.firstKey());  // apple\nSystem.out.println(map.lastKey());   // cherry\nSystem.out.println(map.subMap("b", "d")); // banana, cherry', keyPoints: ['Sorted order (red-black tree)', 'O(log n) operations', 'firstKey/lastKey/headMap/subMap', 'Comparable or Comparator required'] }),
  ]},
  { name: 'Concurrency', concepts: [
    c('Thread Lifecycle', 'Intermediate', 'Thread states: NEW, RUNNABLE, BLOCKED, WAITING, TIMED_WAITING, TERMINATED', { codeExample: 'Thread t = new Thread(() -> {\n    try { Thread.sleep(1000); } catch (InterruptedException e) {\n        Thread.currentThread().interrupt(); }});\nSystem.out.println(t.getState()); // NEW\nt.start();\nSystem.out.println(t.getState()); // RUNNABLE\nt.join();\nSystem.out.println(t.getState()); // TERMINATED', keyPoints: ['NEW: created not started', 'RUNNABLE: executing or ready', 'BLOCKED: waiting for monitor lock', 'WAITING/TIMED_WAITING for join/sleep'] }),
    c('synchronized & Locks', 'Intermediate', 'Controlling thread access to shared resources to prevent race conditions', { codeExample: 'public class Counter {\n    private int count = 0;\n\n    public synchronized void increment() { count++; }\n\n    private final Lock lock = new ReentrantLock();\n    public void decrement() {\n        lock.lock();\n        try { count--; }\n        finally { lock.unlock(); }\n    }\n}', keyPoints: ['synchronized on method or block', 'ReentrantLock with try/finally', 'ReadWriteLock for read-heavy', 'Consistent lock ordering avoids deadlocks'] }),
    c('ExecutorService & Thread Pools', 'Intermediate', 'Higher-level API for managing thread lifecycle and task execution', { codeExample: 'ExecutorService executor = Executors.newFixedThreadPool(4);\nFuture<String> future = executor.submit(() -> {\n    Thread.sleep(1000);\n    return "Result";\n});\n\nString result = future.get(5, TimeUnit.SECONDS);\n\nList<Future<String>> futures = executor.invokeAll(List.of(\n    () -> "Task 1", () -> "Task 2"\n));\n\nexecutor.shutdown();\nexecutor.awaitTermination(10, TimeUnit.SECONDS);', keyPoints: ['Thread pool reduces overhead', 'submit() returns Future', 'invokeAll/invokeAny for batch', 'Always shutdown executor'] }),
    c('Atomic Variables & volatile', 'Intermediate', 'Using Atomic classes and volatile for thread-safe operations', { codeExample: 'import java.util.concurrent.atomic.*;\n\npublic class AtomicCounter {\n    private final AtomicInteger count = new AtomicInteger(0);\n\n    public void increment() { count.incrementAndGet(); }\n    public int get() { return count.get(); }\n}\n\npublic class Flag {\n    private volatile boolean running = true;\n    public void stop() { running = false; }\n}', keyPoints: ['AtomicInteger for CAS ops', 'volatile ensures visibility', 'Atomic vs synchronized trade-offs'] }),
    c('Deadlock Prevention', 'Advanced', 'Techniques to avoid deadlocks where threads wait indefinitely for resources', { codeExample: '// Deadlock-prone: opposite lock order\npublic void method1() {\n    synchronized(a) { synchronized(b) { } }\n}\npublic void method2() {\n    synchronized(b) { synchronized(a) { } } // danger!\n}\n\n// Fix: consistent lock ordering\n// Or: tryLock with timeout', keyPoints: ['Four conditions: ME, H&W, NP, CW', 'Consistent lock ordering', 'tryLock() with timeout', 'jstack for detection'], followUps: ['How to detect deadlocks in production?'] }),
  ]},
  { name: 'JVM & Memory', concepts: [
    c('Java Memory Model (JMM)', 'Advanced', 'Defines how threads interact through memory and when changes are visible', { keyPoints: ['Happens-before relationship', 'Volatile guarantees visibility', 'Synchronized establishes happens-before', 'Reordering can cause surprising behavior'] }),
    c('Class Loading & Reflection', 'Advanced', 'Dynamic class loading, runtime type inspection, and method invocation via Reflection', { codeExample: 'Class<?> clazz = Class.forName("com.example.User");\nMethod[] methods = clazz.getDeclaredMethods();\nObject obj = clazz.getDeclaredConstructor().newInstance();\nMethod m = clazz.getMethod("getName");\nString name = (String) m.invoke(obj);\n\nField field = clazz.getDeclaredField("secret");\nfield.setAccessible(true);\nfield.set(obj, "newValue");', keyPoints: ['Class.forName() dynamic loading', 'getMethods/getFields introspection', 'Method.invoke() dynamic call', 'Performance overhead'] }),
    c('JIT Compiler', 'Advanced', 'Just-In-Time compilation converts bytecode to native machine code at runtime', { keyPoints: ['C1 (client) and C2 (server) compilers', 'Tiered compilation', 'Inline caching, loop unrolling, escape analysis', 'Profile-guided optimization'] }),
    c('Heap & Stack Memory', 'Intermediate', 'JVM memory divided into heap (objects) and stack (method frames, local variables)', { codeExample: '// -Xms512m -Xmx2g (heap sizing)\n// -Xss1m (stack size per thread)\n\npublic void method() {\n    int x = 10;        // stack\n    String s = "hello"; // ref: stack, obj: heap\n}', keyPoints: ['Heap: shared across threads', 'Stack: per-thread, fixed size', 'StackOverflowError from recursion', 'OutOfMemoryError heap exhaustion'] }),
  ]},
  { name: 'I/O & NIO', concepts: [
    c('Stream I/O', 'Intermediate', 'Byte and character streams for reading/writing data', { codeExample: 'FileInputStream fis = new FileInputStream("file.bin");\nint data;\nwhile ((data = fis.read()) != -1) {\n    System.out.print((char) data);\n}\nfis.close();\n\ntry (BufferedReader br = new BufferedReader(\n        new FileReader("file.txt"))) {\n    String line;\n    while ((line = br.readLine()) != null) {\n        System.out.println(line);\n    }\n}\n\nBufferedWriter bw = new BufferedWriter(new FileWriter("out.txt"));\nbw.write("Hello World");\nbw.close();', keyPoints: ['InputStream/OutputStream binary', 'Reader/Writer text', 'Buffered streams for performance', 'Try-with-resources'] }),
    c('NIO (Non-blocking I/O)', 'Advanced', 'Channel-based, buffer-oriented I/O for high-performance operations', { codeExample: 'RandomAccessFile file = new RandomAccessFile("data.txt", "rw");\nFileChannel channel = file.getChannel();\n\nByteBuffer buffer = ByteBuffer.allocate(1024);\nint bytesRead = channel.read(buffer);\nwhile (bytesRead != -1) {\n    buffer.flip();\n    while (buffer.hasRemaining()) {\n        System.out.print((char) buffer.get());\n    }\n    buffer.clear();\n    bytesRead = channel.read(buffer);\n}\nchannel.close();\n\nSelector selector = Selector.open();\nServerSocketChannel.open()\n    .bind(new InetSocketAddress(8080))\n    .configureBlocking(false)\n    .register(selector, SelectionKey.OP_ACCEPT);', keyPoints: ['Channels and Buffers vs Streams', 'Selectors for multiplexing', 'Non-blocking mode', 'Memory-mapped files'] }),
  ]},
  { name: 'Modern Java (8+)', concepts: [
    c('Lambda Expressions', 'Intermediate', 'Anonymous functions enabling functional programming patterns', { codeExample: 'button.addActionListener(e -> System.out.println("Clicked"));\n\nList<String> names = Arrays.asList("Alice", "Bob", "Charlie");\nnames.stream()\n    .filter(name -> name.startsWith("A"))\n    .map(String::toUpperCase)\n    .forEach(System.out::println);', keyPoints: ['(params) -> expression syntax', 'Functional interfaces (SAM)', 'Method references (ClassName::method)', 'Effectively final'] }),
    c('Stream API', 'Intermediate', 'Functional operations on sequences for declarative data processing', { codeExample: 'List<Order> orders = getOrders();\n\nMap<String, Double> result = orders.stream()\n    .filter(o -> o.getAmount() > 100)\n    .collect(Collectors.groupingBy(\n        Order::getCategory,\n        Collectors.averagingDouble(Order::getAmount)\n    ));\n\norders.parallelStream()\n    .map(this::processExpensive)\n    .collect(Collectors.toList());', keyPoints: ['Intermediate: filter, map, flatMap', 'Terminal: collect, forEach, reduce', 'Lazy evaluation', 'Parallel streams'] }),
    c('Optional', 'Intermediate', 'Container that may or may not contain a value, reducing null pointer exceptions', { codeExample: 'public Optional<User> findUser(String email) {\n    return Optional.ofNullable(userDatabase.get(email));\n}\n\nfindUser("alice@example.com")\n    .map(User::getAddress)\n    .map(Address::getCity)\n    .ifPresentOrElse(\n        city -> System.out.println(city),\n        () -> System.out.println("City not found")\n    );\n\nUser user = findUser(email)\n    .orElseThrow(() -> new NotFoundException("User not found"));', keyPoints: ['Avoids null checks', 'map, filter, flatMap operations', 'orElse, orElseGet, orElseThrow'] }),
    c('Date & Time API', 'Intermediate', 'Modern date/time API (java.time) replacing Date and Calendar', { codeExample: 'import java.time.*;\nimport java.time.format.*;\n\nLocalDate today = LocalDate.now();\nLocalTime now = LocalTime.now();\n\nDateTimeFormatter fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd");\nLocalDate parsed = LocalDate.parse("2024-01-15", fmt);\n\nDuration duration = Duration.ofHours(2);\nPeriod period = Period.between(birthDate, today);\n\nZonedDateTime zdt = ZonedDateTime.now(ZoneId.of("America/New_York"));', keyPoints: ['Immutable and thread-safe', 'Separate date/time/datetime', 'Duration vs Period', 'Thread-safe formatters'] }),
    c('Records & Sealed Classes', 'Intermediate', 'Records: transparent data carriers. Sealed classes: restricted inheritance.', { codeExample: 'public record Point(int x, int y) { }\n\npublic sealed class Shape permits Circle, Rectangle { }\nfinal class Circle extends Shape { }\nfinal class Rectangle extends Shape { }\n\ndouble area = switch (shape) {\n    case Circle c -> Math.PI * c.radius() * c.radius();\n    case Rectangle r -> r.width() * r.height();\n};', keyPoints: ['Records: immutable, compact', 'Sealed classes: exhaustive matching', 'Pattern matching switch'] }),
  ]},
]);
// ========== REACT (30 concepts) ==========
course('react', 'React', 'fab fa-react', '#61DAFB', [
  { name: 'Core React', concepts: [
    c('JSX Syntax', 'Beginner', 'JavaScript XML syntax that allows writing HTML-like code in JavaScript', { codeExample: 'function Welcome({ name }) {\n  return (\n    <div className="welcome">\n      <h1>Hello, {name}</h1>\n      {name.length > 0 && <p>Long name!</p>}\n    </div>\n  );\n}', keyPoints: ['Syntactic sugar for createElement', '{} for JS expressions', 'className instead of class'] }),
    c('Components & Props', 'Beginner', 'Reusable UI pieces that accept inputs (props) and return React elements', { codeExample: 'function Greeting({ name, age = 18 }) {\n  return <p>Hello {name}, age {age}</p>;\n}\n\nclass Welcome extends React.Component {\n  render() {\n    return <h1>Welcome, {this.props.name}</h1>;\n  }\n}', keyPoints: ['Props are read-only', 'Children via props.children', 'Composition over inheritance'] }),
    c('State & Lifecycle', 'Intermediate', 'Managing local component state with hooks and understanding lifecycle', { codeExample: 'import { useState, useEffect } from "react";\n\nfunction Timer() {\n  const [seconds, setSeconds] = useState(0);\n\n  useEffect(() => {\n    const id = setInterval(() => {\n      setSeconds(s => s + 1);\n    }, 1000);\n    return () => clearInterval(id);\n  }, []);\n\n  return <div>{seconds}s</div>;\n}', keyPoints: ['useState returns [value, setter]', 'Functional updates', 'Effects run after render', 'Cleanup on unmount'] }),
    c('Virtual DOM & Reconciliation', 'Intermediate', 'In-memory representation of real DOM used for efficient updates', { keyPoints: ['VDOM tree on every render', 'Diffing compares old vs new', 'Keys for element identity', 'Minimal DOM mutations'] }),
    c('Conditional Rendering', 'Beginner', 'Techniques for rendering components based on state or props', { codeExample: 'function UserStatus({ user }) {\n  if (!user) return <LoginButton />;\n\n  return (\n    <div>\n      <h2>Welcome {user.name}</h2>\n      {user.isAdmin && <AdminPanel />}\n      {user.notifications.length > 0\n        ? <Badge count={user.notifications.length} />\n        : <p>No notifications</p>\n      }\n    </div>\n  );\n}', keyPoints: ['if/else returns JSX', 'Ternary for inline', '&& for short-circuit', 'null renders nothing'] }),
    c('Forms & Controlled Components', 'Intermediate', 'Form inputs controlled by React state as single source of truth', { codeExample: 'function LoginForm() {\n  const [form, setForm] = useState({ email: "", password: "" });\n\n  function handleChange(e) {\n    const { name, value } = e.target;\n    setForm(prev => ({ ...prev, [name]: value }));\n  }\n\n  function handleSubmit(e) {\n    e.preventDefault();\n    submitApi(form);\n  }\n\n  return (\n    <form onSubmit={handleSubmit}>\n      <input name="email" value={form.email} onChange={handleChange} />\n      <button type="submit">Login</button>\n    </form>\n  );\n}', keyPoints: ['Value controlled by state', 'onChange handler updates state', 'Validation with state'] }),
  ]},
  { name: 'Hooks', concepts: [
    c('useEffect Deep Dive', 'Intermediate', 'Managing side effects: data fetching, subscriptions, DOM manipulation', { codeExample: 'function UserProfile({ userId }) {\n  const [user, setUser] = useState(null);\n  const [loading, setLoading] = useState(true);\n\n  useEffect(() => {\n    let cancelled = false;\n    setLoading(true);\n\n    fetch(`/api/users/${userId}`)\n      .then(res => res.json())\n      .then(data => {\n        if (!cancelled) {\n          setUser(data);\n          setLoading(false);\n        }\n      });\n\n    return () => { cancelled = true; };\n  }, [userId]);\n\n  if (loading) return <Spinner />;\n  return <div>{user?.name}</div>;\n}', keyPoints: ['Runs after every render by default', 'Empty deps = mount/unmount', 'Cleanup for subscriptions', 'Race condition handling'] }),
    c('Custom Hooks', 'Intermediate', 'Extracting component logic into reusable functions that use other hooks', { codeExample: 'function useDebounce(value, delay) {\n  const [debounced, setDebounced] = useState(value);\n\n  useEffect(() => {\n    const timer = setTimeout(() => setDebounced(value), delay);\n    return () => clearTimeout(timer);\n  }, [value, delay]);\n\n  return debounced;\n}\n\nfunction useLocalStorage(key, initial) {\n  const [value, setValue] = useState(() => {\n    const stored = localStorage.getItem(key);\n    return stored ? JSON.parse(stored) : initial;\n  });\n\n  useEffect(() => {\n    localStorage.setItem(key, JSON.stringify(value));\n  }, [key, value]);\n\n  return [value, setValue];\n}', keyPoints: ['Start with "use" prefix', 'Can call other hooks inside', 'Share stateful logic, not state'] }),
    c('useRef & forwardRef', 'Intermediate', 'Mutable ref objects that persist across renders without causing re-renders', { codeExample: 'function AutoFocus() {\n  const inputRef = useRef(null);\n\n  useEffect(() => {\n    inputRef.current?.focus();\n  }, []);\n\n  return <input ref={inputRef} />;\n}\n\nconst FancyInput = forwardRef((props, ref) => {\n  return <input ref={ref} className="fancy" {...props} />;\n});', keyPoints: ['Mutable .current property', 'Does not trigger re-render', 'forwardRef passes ref to child'] }),
    c('useReducer & useCallback', 'Intermediate', 'useReducer for complex state, useCallback for memoized callbacks', { codeExample: 'function reducer(state, action) {\n  switch (action.type) {\n    case "INCREMENT": return { count: state.count + 1 };\n    case "DECREMENT": return { count: state.count - 1 };\n    case "RESET": return { count: 0 };\n    default: return state;\n  }\n}\n\nfunction Counter() {\n  const [state, dispatch] = useReducer(reducer, { count: 0 });\n  const handleClick = useCallback(() => {\n    dispatch({ type: "INCREMENT" });\n  }, []);\n\n  return <button onClick={handleClick}>{state.count}</button>;\n}', keyPoints: ['useReducer for complex state', 'dispatch is stable', 'useCallback memoizes function'] }),
    c('useContext', 'Intermediate', 'Share data across component tree without prop drilling', { codeExample: 'const ThemeContext = createContext("light");\n\nfunction App() {\n  const [theme, setTheme] = useState("dark");\n\n  return (\n    <ThemeContext.Provider value={{ theme, setTheme }}>\n      <MainContent />\n    </ThemeContext.Provider>\n  );\n}\n\nfunction MainContent() {\n  const { theme, setTheme } = useContext(ThemeContext);\n\n  return (\n    <div className={theme}>\n      <button onClick={() => setTheme(t => t === "dark" ? "light" : "dark")}>\n        Toggle\n      </button>\n    </div>\n  );\n}', keyPoints: ['createContext + Provider', 'useContext consumes nearest', 'Avoid over-use (causes re-renders)'] }),
  ]},
  { name: 'State Management', concepts: [
    c('Lifting State Up', 'Beginner', 'Moving shared state to the nearest common ancestor for sibling communication', { codeExample: 'function Parent() {\n  const [selectedId, setSelectedId] = useState(null);\n\n  return (\n    <div>\n      <ItemList onSelect={setSelectedId} />\n      <ItemDetail id={selectedId} />\n    </div>\n  );\n}', keyPoints: ['Single source of truth', 'Parent manages state', 'Children receive callbacks'] }),
    c('Redux Architecture', 'Advanced', 'Predictable state container with actions, reducers, and a single immutable store', { codeExample: 'const increment = (amount) => ({\n  type: "counter/increment",\n  payload: amount\n});\n\nconst counterReducer = (state = { value: 0 }, action) => {\n  switch (action.type) {\n    case "counter/increment":\n      return { ...state, value: state.value + action.payload };\n    default:\n      return state;\n  }\n};\n\nconst store = configureStore({\n  reducer: { counter: counterReducer }\n});\n\nfunction Counter() {\n  const count = useSelector(state => state.counter.value);\n  const dispatch = useDispatch();\n  return <button onClick={() => dispatch(increment(1))}>{count}</button>;\n}', keyPoints: ['Single immutable store', 'Actions describe events', 'Reducers compute new state', 'RTK simplifies boilerplate'] }),
    c('Zustand & Jotai', 'Intermediate', 'Lightweight state management alternatives to Redux', { codeExample: 'import { create } from "zustand";\n\nconst useStore = create((set) => ({\n  count: 0,\n  increment: () => set(state => ({ count: state.count + 1 })),\n}));\n\nfunction Counter() {\n  const { count, increment } = useStore();\n  return <button onClick={increment}>{count}</button>;\n}', keyPoints: ['Zustand: minimal API, no providers', 'Jotai: atomic composable state', 'Both avoid Redux boilerplate'], followUps: ['Zustand vs Redux - when to use each?'] }),
  ]},
  { name: 'Performance', concepts: [
    c('React.memo & useMemo', 'Advanced', 'Preventing unnecessary re-renders of expensive components', { codeExample: 'const Expensive = React.memo(function({ data, onClick }) {\n  return <div onClick={onClick}>{computeExpensive(data)}</div>;\n});\n\nfunction Parent({ items }) {\n  const sorted = useMemo(() => {\n    return [...items].sort((a, b) => a.name.localeCompare(b.name));\n  }, [items]);\n\n  const handleClick = useCallback((id) => {\n    console.log("Clicked", id);\n  }, []);\n\n  return <Expensive data={sorted} onClick={handleClick} />;\n}', keyPoints: ['React.memo: shallow prop comparison', 'useMemo caches computed values', 'useCallback caches function refs'] }),
    c('Code Splitting & Lazy Loading', 'Intermediate', 'Splitting code into chunks loaded on demand to reduce bundle size', { codeExample: 'import { lazy, Suspense } from "react";\n\nconst Dashboard = lazy(() => import("./Dashboard"));\nconst Settings = lazy(() => import("./Settings"));\n\nfunction App() {\n  return (\n    <Suspense fallback={<LoadingSpinner />}>\n      <Routes>\n        <Route path="/dashboard" element={<Dashboard />} />\n        <Route path="/settings" element={<Settings />} />\n      </Routes>\n    </Suspense>\n  );\n}', keyPoints: ['React.lazy() for dynamic imports', 'Suspense for loading states', 'Route-based splitting'] }),
    c('Virtualization', 'Advanced', 'Rendering only visible items in long lists for performance', { codeExample: 'import { FixedSizeList } from "react-window";\n\nfunction VirtualList({ items }) {\n  const Row = ({ index, style }) => (\n    <div style={style}>{items[index].name}</div>\n  );\n\n  return (\n    <FixedSizeList height={400} itemCount={items.length} itemSize={50} width={300}>\n      {Row}\n    </FixedSizeList>\n  );\n}', keyPoints: ['Renders visible window + overscan', 'Handles 100,000+ items', 'react-window, react-virtualized'] }),
    c('Rendering Optimization Patterns', 'Intermediate', 'Minimizing re-renders with component composition and state colocation', { codeExample: '// Bad: state change re-renders entire tree\nfunction App() {\n  const [count, setCount] = useState(0);\n  return (\n    <div>\n      <CounterDisplay count={count} />\n      <ExpensiveTree />  {/* Re-renders every time! */}\n    </div>\n  );\n}\n\n// Good: colocate state\nfunction App() {\n  return (\n    <div>\n      <CounterWrapper />\n      <ExpensiveTree />  {/* Stable */}\n    </div>\n  );\n}', keyPoints: ['Colocate state where needed', 'Lift content up pattern', 'Stable keys prevent remounts'] }),
  ]},
]);

// ========== SQL (30 concepts) ==========
course('sql', 'SQL', 'fas fa-database', '#336791', [
  { name: 'Query Fundamentals', concepts: [
    c('SELECT & Filtering', 'Beginner', 'Retrieving rows with WHERE clause, operators, and pattern matching', { codeExample: 'SELECT first_name, last_name, salary\nFROM employees\nWHERE department_id = 5\n  AND salary >= 50000\n  AND last_name LIKE "Sm%"\n  AND hire_date BETWEEN "2020-01-01" AND "2023-12-31"\n  AND region IN ("North", "East")\nORDER BY salary DESC\nLIMIT 10;', keyPoints: ['SELECT specifies columns', 'WHERE filters rows', 'LIKE for pattern matching', 'BETWEEN, IN, IS NULL'] }),
    c('JOINs (INNER, LEFT, RIGHT, FULL)', 'Intermediate', 'Combining rows from related tables using join conditions', { codeExample: 'SELECT e.name, d.department_name, s.amount\nFROM employees e\nINNER JOIN departments d ON e.dept_id = d.id\nLEFT JOIN salaries s ON e.id = s.employee_id\n  AND s.effective_date = CURRENT_DATE\nWHERE s.amount > 50000\nORDER BY s.amount DESC;', keyPoints: ['INNER: matching only', 'LEFT: all left + matching right', 'RIGHT: all right + matching left', 'FULL: all rows'] }),
    c('Subqueries & CTEs', 'Intermediate', 'Nested queries and Common Table Expressions for modular query composition', { codeExample: '-- Subquery in WHERE\nSELECT name, salary\nFROM employees\nWHERE salary > (SELECT AVG(salary) FROM employees);\n\n-- CTE\nWITH dept_avg AS (\n    SELECT dept_id, AVG(salary) AS avg_sal\n    FROM employees GROUP BY dept_id\n)\nSELECT e.name, e.salary, da.avg_sal\nFROM employees e\nJOIN dept_avg da ON e.dept_id = da.dept_id\nWHERE e.salary > da.avg_sal;', keyPoints: ['Subqueries in SELECT/FROM/WHERE', 'CTEs for readability/recursion', 'Correlated vs non-correlated', 'EXISTS vs IN'] }),
    c('Aggregation & GROUP BY', 'Intermediate', 'Grouping rows and computing aggregate functions', { codeExample: 'SELECT\n    department_id,\n    COUNT(*) AS employee_count,\n    AVG(salary) AS avg_salary,\n    MAX(salary) AS max_salary\nFROM employees\nWHERE active = 1\nGROUP BY department_id\nHAVING AVG(salary) > 55000\nORDER BY avg_salary DESC;', keyPoints: ['GROUP BY collapses by columns', 'HAVING filters groups', 'WHERE filters before aggregation', 'COUNT(*) vs COUNT(column)'] }),
    c('String & Date Functions', 'Intermediate', 'Built-in functions for manipulating string and date/time values', { codeExample: 'SELECT\n    UPPER(last_name),\n    CONCAT(first_name, " ", last_name) AS full_name,\n    SUBSTRING(email, 1, POSITION("@" IN email) - 1) AS username,\n    LENGTH(phone) AS phone_digits,\n    CURRENT_DATE AS today,\n    DATE_ADD(hire_date, INTERVAL 1 YEAR) AS anniversary,\n    DATEDIFF(CURRENT_DATE, hire_date) AS days_employed\nFROM employees\nWHERE YEAR(hire_date) = 2023;', keyPoints: ['CONCAT, SUBSTRING, REPLACE', 'DATE_ADD, DATEDIFF, DATE_FORMAT', 'COALESCE for NULL', 'CAST for conversion'] }),
  ]},
  { name: 'Advanced Queries', concepts: [
    c('Window Functions', 'Advanced', 'Calculations across rows related to current row without collapsing', { codeExample: 'SELECT\n    name, department, salary,\n    ROW_NUMBER() OVER (PARTITION BY dept ORDER BY salary DESC) AS rank,\n    RANK() OVER (ORDER BY salary DESC) AS overall_rank,\n    LAG(salary, 1) OVER (PARTITION BY dept ORDER BY hire_date) AS prev_salary,\n    AVG(salary) OVER (PARTITION BY dept) AS dept_avg\nFROM employees;', keyPoints: ['ROW_NUMBER, RANK, DENSE_RANK', 'LAG/LEAD for adjacent rows', 'PARTITION BY defines windows', 'ROWS vs RANGE frame'] }),
    c('Set Operations', 'Intermediate', 'Combining results from multiple queries with UNION, INTERSECT, EXCEPT', { codeExample: '-- UNION (deduped)\nSELECT city FROM customers\nUNION\nSELECT city FROM suppliers;\n\n-- UNION ALL (faster)\nSELECT product_id FROM orders\nUNION ALL\nSELECT product_id FROM returns;\n\n-- INTERSECT\nSELECT employee_id FROM project_alpha\nINTERSECT\nSELECT employee_id FROM project_beta;\n\n-- EXCEPT\nSELECT employee_id FROM all_staff\nEXCEPT\nSELECT employee_id FROM terminated;', keyPoints: ['UNION removes duplicates', 'Same column count required', 'Names from first query', 'ORDER BY on final result'] }),
    c('Recursive CTEs', 'Advanced', 'CTEs that reference themselves for hierarchical or graph data traversal', { codeExample: 'WITH RECURSIVE org_tree AS (\n    -- Anchor\n    SELECT id, name, manager_id, 1 AS level\n    FROM employees WHERE manager_id IS NULL\n\n    UNION ALL\n\n    -- Recursive\n    SELECT e.id, e.name, e.manager_id, ot.level + 1\n    FROM employees e\n    JOIN org_tree ot ON e.manager_id = ot.id\n)\nSELECT * FROM org_tree ORDER BY level, name;', keyPoints: ['Anchor member (base)', 'Recursive member references CTE', 'UNION ALL combines', 'Stops when empty'] }),
    c('PIVOT / Crosstab', 'Advanced', 'Transforming rows into columns for cross-tabulation reports', { codeExample: '-- Manual pivot with CASE\nSELECT\n    department,\n    SUM(CASE WHEN gender = "M" THEN 1 ELSE 0 END) AS male_count,\n    SUM(CASE WHEN gender = "F" THEN 1 ELSE 0 END) AS female_count,\n    COUNT(*) AS total\nFROM employees\nGROUP BY department;', keyPoints: ['CASE for manual pivot', 'FILTER clause (PostgreSQL)', 'CROSSTAB function'] }),
  ]},
  { name: 'Optimization & Indexing', concepts: [
    c('Index Types & Usage', 'Advanced', 'Data structures for fast data access: B-Tree, Hash, GiST, GIN, BRIN', { codeExample: '-- B-Tree (default)\nCREATE INDEX idx_last_name ON employees(last_name);\n\n-- Composite (column order matters!)\nCREATE INDEX idx_customer_date ON orders(customer_id, order_date DESC);\n\n-- Partial index\nCREATE INDEX idx_active ON users(email) WHERE active = true;\n\n-- Check usage\nEXPLAIN ANALYZE SELECT * FROM employees WHERE last_name = "Smith";', keyPoints: ['B-Tree for range/equality', 'Composite index column order', 'Partial indexes save space', 'EXPLAIN ANALYZE check'] }),
    c('Query Execution Plan', 'Advanced', 'Using EXPLAIN ANALYZE to understand how the database executes queries', { codeExample: 'EXPLAIN ANALYZE\nSELECT d.name, COUNT(e.id) AS emp_count\nFROM departments d\nLEFT JOIN employees e ON e.dept_id = d.id\nWHERE d.active = 1\nGROUP BY d.name\nHAVING COUNT(e.id) > 5\nORDER BY emp_count DESC;\n\n-- Look for:\n-- Seq Scan (need index?)\n-- Index Scan (efficient)\n-- Hash vs Nested Loop vs Merge Join', keyPoints: ['Seq Scan means full table scan', 'Index Scan is efficient', 'Join type affects perf', 'High cost nodes'] }),
    c('Normalization & Denormalization', 'Intermediate', 'Designing schemas to reduce redundancy or improve read performance', { codeExample: '-- Normalized (3NF)\n-- customers: customer_id, name, email\n-- orders: order_id, customer_id, order_date\n-- order_items: order_item_id, order_id, product_id, qty, price\n\n-- Denormalized (read-optimized)\n-- orders: order_id, customer_name, product_names, total', keyPoints: ['1NF: atomic columns', '2NF: full functional dependency', '3NF: no transitive deps', 'Denormalize for read perf'] }),
  ]},
  { name: 'Administration', concepts: [
    c('Transactions & ACID', 'Intermediate', 'Atomic, Consistent, Isolated, Durable transactions for reliable modifications', { codeExample: 'BEGIN TRANSACTION;\nUPDATE accounts SET balance = balance - 100 WHERE id = 1;\nUPDATE accounts SET balance = balance + 100 WHERE id = 2;\n\nSAVEPOINT before_update;\nUPDATE ...;\nIF error ROLLBACK TO SAVEPOINT;\n\nCOMMIT;\n\n-- Isolation levels:\n-- READ UNCOMMITTED, READ COMMITTED,\n-- REPEATABLE READ, SERIALIZABLE', keyPoints: ['Atomicity: all or nothing', 'Consistency: valid state', 'Isolation: no interference', 'Durability: persist'] }),
    c('Backup & Recovery', 'Intermediate', 'Strategies for backing up databases and recovering from failures', { codeExample: '-- Logical backup\npg_dump mydb > mydb_backup.sql\npsql mydb < mydb_backup.sql\n\n-- Physical backup\n-- Point-in-Time Recovery (PITR)\n-- wal_level = replica (WAL archiving)\n\nmysqldump --all-databases --master-data > backup.sql', keyPoints: ['Logical vs physical backups', 'Full + incremental + differential', 'PITR', 'Test restores regularly!'] }),
    c('User Management & Permissions', 'Beginner', 'Creating users, granting privileges, and managing access control', { codeExample: 'CREATE USER "app_user"@"localhost" IDENTIFIED BY "secure_password";\nGRANT SELECT, INSERT ON mydb.* TO "app_user"@"localhost";\nGRANT ALL PRIVILEGES ON mydb.* TO "admin"@"localhost" WITH GRANT OPTION;\nREVOKE DELETE ON mydb.* FROM "app_user"@"localhost";\n\nCREATE ROLE readonly;\nGRANT SELECT ON ALL TABLES IN SCHEMA public TO readonly;\nGRANT readonly TO app_user;', keyPoints: ['Least privilege principle', 'Grant only necessary perms', 'Use roles for groups', 'Audit permissions regularly'] }),
  ]},
]);
// ========== HTML (20 concepts) ==========
course('html', 'HTML', 'fab fa-html5', '#E34F26', [
  { name: 'HTML Basics', concepts: [
    c('Semantic HTML', 'Beginner', 'Using HTML elements that convey meaning about their content for accessibility and SEO', { codeExample: '<header>\n  <nav aria-label="Main navigation">\n    <ul>\n      <li><a href="/">Home</a></li>\n    </ul>\n  </nav>\n</header>\n<main>\n  <article>\n    <h1>Article Title</h1>\n    <section>\n      <h2>Section</h2>\n      <p>Content</p>\n    </section>\n    <aside>Related</aside>\n  </article>\n</main>\n<footer>&copy; 2026</footer>', keyPoints: ['Improves accessibility', 'Better SEO', 'Semantic: header, nav, main, article, section, aside, footer'], commonMistakes: ['div for everything', 'Skipping heading levels', 'Missing alt on images'] }),
    c('Document Structure', 'Beginner', 'Required elements: DOCTYPE, html, head, body forming page skeleton', { codeExample: '<!DOCTYPE html>\n<html lang="en">\n<head>\n  <meta charset="UTF-8">\n  <meta name="viewport" content="width=device-width, initial-scale=1.0">\n  <title>My Page</title>\n  <link rel="stylesheet" href="styles.css">\n</head>\n<body>\n  <script src="app.js" defer></script>\n</body>\n</html>', keyPoints: ['<!DOCTYPE html> for HTML5', '<meta charset> for encoding', 'Viewport for responsive', 'defer for scripts'] }),
    c('Forms & Input Types', 'Intermediate', 'Collecting and validating user input with various input types and attributes', { codeExample: '<form action="/submit" method="POST" novalidate>\n  <label for="email">Email:</label>\n  <input type="email" id="email" name="email" required\n         pattern="[a-z0-9._%+-]+@[a-z0-9.-]+\\.[a-z]{2,}$">\n  <label for="age">Age:</label>\n  <input type="number" id="age" name="age" min="1" max="150">\n  <select id="country" name="country">\n    <option value="US">US</option>\n    <option value="IN">India</option>\n  </select>\n  <button type="submit">Submit</button>\n</form>', keyPoints: ['input types: email, number, url, date, file', 'Attributes: required, min, max, pattern', 'label for accessibility'] }),
    c('Tables', 'Beginner', 'Structuring tabular data with table, thead, tbody, th, td', { codeExample: '<table>\n  <caption>Monthly Sales</caption>\n  <thead>\n    <tr><th scope="col">Product</th><th scope="col">Q1</th></tr>\n  </thead>\n  <tbody>\n    <tr><th scope="row">Widget</th><td>100</td></tr>\n  </tbody>\n  <tfoot>\n    <tr><td colspan="2">Total: 100</td></tr>\n  </tfoot>\n</table>', keyPoints: ['caption for title', 'scope for accessibility', 'colspan/rowspan for spanning'] }),
    c('Multimedia Elements', 'Beginner', 'Embedding images, audio, and video with fallback and accessibility', { codeExample: '<picture>\n  <source media="(min-width: 800px)" srcset="large.jpg">\n  <source media="(min-width: 400px)" srcset="medium.jpg">\n  <img src="small.jpg" alt="Description" loading="lazy">\n</picture>\n\n<video controls width="640">\n  <source src="video.mp4" type="video/mp4">\n  <source src="video.webm" type="video/webm">\n  Your browser does not support video.\n</video>\n\n<audio controls>\n  <source src="audio.mp3" type="audio/mpeg">\n</audio>', keyPoints: ['alt attribute required on img', 'picture for responsive images', 'loading="lazy" for perf', 'Multiple sources for fallback'] }),
    c('Links & Navigation', 'Beginner', 'Creating hyperlinks with a element, targeting, and accessibility attributes', { codeExample: '<a href="https://example.com" target="_blank" rel="noopener noreferrer">\n  External Link\n</a>\n<a href="#section-id">Internal Link</a>\n<a href="mailto:user@example.com">Email</a>\n<a href="tel:+1234567890">Call</a>\n\n<nav aria-label="Breadcrumb">\n  <ol>\n    <li><a href="/">Home</a></li>\n    <li><a href="/products">Products</a></li>\n    <li aria-current="page">Current</li>\n  </ol>\n</nav>', keyPoints: ['href for URL target', 'target="_blank" needs rel="noopener"', 'aria-current for active', 'Skip nav links for a11y'] }),
  ]},
  { name: 'Accessibility & SEO', concepts: [
    c('ARIA Attributes', 'Intermediate', 'Accessible Rich Internet Applications attributes for enhancing accessibility', { codeExample: '<button aria-label="Close dialog" onclick="close()">X</button>\n\n<div role="alert" aria-live="polite">\n  Form submitted successfully!\n</div>\n\n<div role="tabpanel" aria-labelledby="tab1">\n  Tab content\n</div>\n\n<input aria-invalid="true" aria-describedby="error-msg">\n<span id="error-msg" role="alert">Invalid input</span>', keyPoints: ['aria-label for icon buttons', 'aria-live for dynamic content', 'role for custom elements', 'aria-describedby for help text'] }),
    c('SEO Meta Tags', 'Beginner', 'Meta tags that help search engines understand and rank page content', { codeExample: '<head>\n  <title>Product Name - Best Widgets Online</title>\n  <meta name="description" content="Buy the best widgets online. Free shipping.">\n  <meta name="keywords" content="widgets, online shopping">\n  <meta name="robots" content="index, follow">\n  <link rel="canonical" href="https://example.com/product">\n\n  <!-- Open Graph -->\n  <meta property="og:title" content="Product Name">\n  <meta property="og:description" content="Best widgets">\n  <meta property="og:image" content="https://example.com/image.jpg">\n\n  <!-- Structured data -->\n  <script type="application/ld+json">\n  {"@context": "https://schema.org", "@type": "Product", "name": "Widget"}\n  </script>\n</head>', keyPoints: ['Title and meta description', 'Open Graph for social sharing', 'Canonical URLs prevent duplicate', 'Schema.org structured data'] }),
    c('Accessible Forms', 'Intermediate', 'Designing forms that are usable by people with disabilities', { codeExample: '<form>\n  <fieldset>\n    <legend>Contact Information</legend>\n\n    <label for="name">Full Name <span aria-hidden="true">*</span></label>\n    <input id="name" required aria-required="true">\n\n    <label for="email">Email</label>\n    <input id="email" type="email" aria-describedby="email-hint">\n    <span id="email-hint" class="hint">We will never share your email</span>\n\n    <fieldset>\n      <legend>Preferred contact method</legend>\n      <label><input type="radio" name="contact"> Phone</label>\n      <label><input type="radio" name="contact"> Email</label>\n    </fieldset>\n\n    <div role="alert" aria-live="assertive" id="form-errors"></div>\n  </fieldset>\n</form>', keyPoints: ['label for each input', 'fieldset + legend for grouping', 'aria-describedby for hints', 'Error summary with role="alert"'] }),
  ]},
  { name: 'Modern HTML Features', concepts: [
    c('Canvas & SVG', 'Intermediate', 'Drawing graphics programmatically with Canvas and scalable vector graphics with SVG', { codeExample: '<canvas id="myCanvas" width="400" height="200"></canvas>\n<script>\n  const ctx = document.getElementById("myCanvas").getContext("2d");\n  ctx.fillStyle = "blue";\n  ctx.fillRect(10, 10, 100, 50);\n  ctx.beginPath();\n  ctx.arc(200, 100, 50, 0, Math.PI * 2);\n  ctx.fillStyle = "red";\n  ctx.fill();\n</script>\n\n<svg width="200" height="100" viewBox="0 0 200 100">\n  <circle cx="50" cy="50" r="40" fill="green" />\n  <rect x="100" y="10" width="80" height="80" rx="10" fill="orange" />\n</svg>', keyPoints: ['Canvas: pixel-based, JavaScript API', 'SVG: vector-based, XML, scalable', 'Canvas better for performance', 'SVG better for accessibility'] }),
    c('Web Components', 'Advanced', 'Custom reusable HTML elements with encapsulated styles and behavior', { codeExample: 'class MyCard extends HTMLElement {\n  constructor() {\n    super();\n    this.attachShadow({ mode: "open" });\n  }\n\n  connectedCallback() {\n    this.shadowRoot.innerHTML = `\n      <style>\n        .card { border: 1px solid #ccc; padding: 1rem; }\n      </style>\n      <div class="card">\n        <slot name="title">Default Title</slot>\n        <slot></slot>\n      </div>\n    `;\n  }\n}\n\ncustomElements.define("my-card", MyCard);', keyPoints: ['Shadow DOM for encapsulation', 'Custom Elements API', 'HTML templates with <slot>', 'Reusable across frameworks'] }),
    c('Dialog & Popover API', 'Intermediate', 'Native dialog and popover elements for modals, tooltips, and overlays', { codeExample: '<!-- Dialog -->\n<dialog id="modal">\n  <h2>Modal Title</h2>\n  <p>Modal content goes here</p>\n  <button onclick="document.getElementById(\'modal\').close()">Close</button>\n</dialog>\n<button onclick="document.getElementById(\'modal\').showModal()">Open Modal</button>\n\n<!-- Popover -->\n<button popovertarget="tooltip">Hover me</button>\n<div id="tooltip" popover>Tooltip content</div>\n\n<!-- Details/Summary (accordion) -->\n<details>\n  <summary>Click to expand</summary>\n  <p>Hidden content revealed</p>\n</details>', keyPoints: ['<dialog> with showModal()/close()', 'popover attribute for tooltips', 'details/summary for expandable', 'Inert background when modal open'] }),
  ]},
]);

// ========== CSS (25 concepts) ==========
course('css', 'CSS', 'fab fa-css3-alt', '#1572B6', [
  { name: 'Layout', concepts: [
    c('Flexbox', 'Intermediate', 'One-dimensional layout model for distributing space among items', { codeExample: '.container {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  gap: 1rem;\n  flex-wrap: wrap;\n}\n.item {\n  flex: 1 1 200px;\n}', keyPoints: ['Main axis (flex-direction)', 'justify-content main axis', 'align-items cross axis', 'flex: grow shrink basis'], commonMistakes: ['Using flexbox for 2D layouts', 'Not setting flex-basis'] }),
    c('CSS Grid', 'Intermediate', 'Two-dimensional layout system for rows and columns', { codeExample: '.grid {\n  display: grid;\n  grid-template-columns: repeat(3, 1fr);\n  gap: 1rem;\n  grid-template-areas:\n    "header header header"\n    "sidebar main main"\n    "footer footer footer";\n}', keyPoints: ['grid-template-columns', 'fr unit', 'grid-template-areas', 'grid-column/grid-row'], commonMistakes: ['Using Grid for 1D layouts', 'auto vs fr sizing confusion'] }),
    c('Positioning', 'Beginner', 'CSS position property: static, relative, absolute, fixed, sticky', { codeExample: '.relative-parent {\n  position: relative;\n}\n.absolute-child {\n  position: absolute;\n  top: 0; left: 0;\n}\n.fixed-header {\n  position: fixed;\n  top: 0; width: 100%;\n  z-index: 100;\n}\n.sticky-nav {\n  position: sticky;\n  top: 0;\n}', keyPoints: ['relative: offset from normal flow', 'absolute: relative to nearest positioned ancestor', 'fixed: relative to viewport', 'sticky: toggles between relative/fixed'] }),
    c('Responsive Design', 'Intermediate', 'Creating layouts that adapt to different screen sizes using media queries', { codeExample: '/* Mobile first */\n.container { display: block; }\n\n/* Tablet */\n@media (min-width: 768px) {\n  .container {\n    display: grid;\n    grid-template-columns: 1fr 2fr;\n  }\n}\n\n/* Desktop */\n@media (min-width: 1024px) {\n  .container {\n    max-width: 1200px;\n    margin: 0 auto;\n  }\n}\n\n/* Dark mode */\n@media (prefers-color-scheme: dark) {\n  body { background: #222; color: #fff; }\n}', keyPoints: ['Mobile-first approach', 'Breakpoints based on content', 'Relative units (%, em, rem, vw, vh)', 'prefers-color-scheme for dark mode'] }),
    c('Float & Clearfix', 'Beginner', 'Legacy layout technique and the clearfix hack for containing floats', { codeExample: '.float-left {\n  float: left;\n  margin-right: 1rem;\n}\n\n/* Clearfix */\n.clearfix::after {\n  content: "";\n  display: table;\n  clear: both;\n}\n\n/* Modern alternative */\n.container {\n  display: flow-root; /* creates BFC */\n}', keyPoints: ['float: left/right for text wrap', 'clearfix for containing floats', 'overflow: hidden alternative', 'display: flow-root modern solution'] }),
  ]},
  { name: 'Styling & Effects', concepts: [
    c('CSS Animations', 'Intermediate', 'Animating elements using @keyframes and animation properties', { codeExample: '@keyframes slideIn {\n  from { transform: translateX(-100%); opacity: 0; }\n  to { transform: translateX(0); opacity: 1; }\n}\n\n@keyframes bounce {\n  0%, 100% { transform: translateY(0); }\n  50% { transform: translateY(-20px); }\n}\n\n.element {\n  animation: slideIn 0.5s ease-out forwards;\n}\n\n.loader {\n  animation: bounce 0.6s ease infinite;\n}', keyPoints: ['@keyframes defines steps', 'animation: name duration timing iteration', 'transform for GPU acceleration', 'transition for simple state changes'] }),
    c('Transitions & Transforms', 'Intermediate', 'Smooth property changes and element transformations', { codeExample: '.btn {\n  background: blue;\n  color: white;\n  transition: all 0.3s ease;\n  transform: scale(1);\n}\n\n.btn:hover {\n  background: darkblue;\n  transform: scale(1.1) translateY(-2px);\n  box-shadow: 0 4px 8px rgba(0,0,0,0.2);\n}\n\n.card {\n  transition: transform 0.3s, box-shadow 0.3s;\n}\n.card:hover {\n  transform: rotateY(180deg);\n}', keyPoints: ['transition: property duration easing', 'transform: translate, scale, rotate, skew', 'GPU accelerated properties', 'transition-delay for staggering'] }),
    c('Pseudo-classes & Pseudo-elements', 'Intermediate', 'Selecting elements based on state or creating virtual elements', { codeExample: '/* Pseudo-classes */\na:link, a:visited, a:hover, a:active { }\ninput:focus { outline: 2px solid blue; }\nli:first-child, li:last-child { }\nli:nth-child(odd) { }\np:empty { display: none; }\n:not(.active) { opacity: 0.5; }\n\n/* Pseudo-elements */\n.quote::before {\n  content: "\\201C";\n  font-size: 2em;\n}\n.quote::after {\n  content: "\\201D";\n}\n.clearfix::after {\n  content: "";\n  display: block;\n  clear: both;\n}\n::selection {\n  background: yellow;\n  color: black;\n}', keyPoints: [':hover, :focus, :active for interaction', ':nth-child() for patterns', '::before and ::after for generated content', '::selection for highlight styling'] }),
    c('Gradients & Shadows', 'Beginner', 'Creating visual effects with gradients and box/text shadows', { codeExample: '.gradient-box {\n  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);\n}\n\n.radial-gradient {\n  background: radial-gradient(circle at center, #ff6b6b, #ee5a24);\n}\n\n.conic-gradient {\n  background: conic-gradient(red, yellow, green, blue, red);\n}\n\n.shadow-box {\n  box-shadow:\n    0 4px 6px rgba(0,0,0,0.1),\n    0 10px 20px rgba(0,0,0,0.15);\n}\n\n.text-shadow {\n  text-shadow: 2px 2px 4px rgba(0,0,0,0.3);\n}', keyPoints: ['linear-gradient: direction + colors', 'radial-gradient: shape + center', 'box-shadow: x y blur spread color', 'Multiple shadows for depth'] }),
    c('Custom Properties (Variables)', 'Intermediate', 'CSS custom properties for reusable values with cascading and inheritance', { codeExample: ':root {\n  --primary: #3498db;\n  --primary-dark: #2980b9;\n  --spacing: 1rem;\n  --radius: 8px;\n  --font-main: "Inter", sans-serif;\n}\n\n.card {\n  background: var(--primary);\n  padding: var(--spacing);\n  border-radius: var(--radius);\n  font-family: var(--font-main);\n  /* Fallback */\n  color: var(--text-color, #333);\n}\n\n@media (prefers-color-scheme: dark) {\n  :root {\n    --primary: #2980b9;\n    --bg: #1a1a2e;\n  }\n}', keyPoints: ['--name defines variable', 'var(--name) uses it', 'Fallback value with var(--name, fallback)', 'Scoped inheritance, updated via JS'] }),
  ]},
  { name: 'Advanced CSS', concepts: [
    c('Specificity & Cascade', 'Intermediate', 'How CSS determines which rules apply when multiple selectors match', { codeExample: '/* Specificity: inline > id > class > element */\n/* 0-0-1 */ p { color: blue; }\n/* 0-1-0 */ .highlight { color: green; }\n/* 1-0-0 */ #unique { color: red; }\n/* 0-1-1 */ p.highlight { color: purple; }\n/* 1-0-1 */ p#unique { color: orange; }\n\n/* !important overrides everything */\n/* Avoid except for utility classes */\n.urgent { color: red !important; }\n\n/* @layer for controlling cascade */\n@layer base, components, utilities;\n\n@layer base {\n  p { margin: 1em 0; }\n}', keyPoints: ['Inline styles > IDs > Classes > Elements', '!important breaks cascade (avoid)', '@layer for explicit ordering', 'Specificity calculator for complex cases'] }),
    c('Container Queries', 'Advanced', 'Applying styles based on container size rather than viewport size', { codeExample: '.card-container {\n  container-type: inline-size;\n  container-name: card;\n}\n\n@container card (min-width: 400px) {\n  .card {\n    display: grid;\n    grid-template-columns: 1fr 2fr;\n  }\n  .card-image { order: -1; }\n  .card-title { font-size: 1.5rem; }\n}\n\n@container card (max-width: 399px) {\n  .card {\n    display: flex;\n    flex-direction: column;\n  }\n}', keyPoints: ['container-type defines containment', 'Query by container size, not viewport', 'Component-level responsive design', 'Named containers for specificity'] }),
    c('CSS Layers (@layer)', 'Advanced', 'Explicitly controlling cascade order with @layer', { codeExample: '@layer reset, base, components, utilities;\n\n@layer reset {\n  *, *::before, *::after {\n    box-sizing: border-box;\n    margin: 0;\n  }\n}\n\n@layer base {\n  body { font-family: system-ui; line-height: 1.6; }\n  a { color: var(--primary); }\n}\n\n@layer components {\n  .card {\n    border: 1px solid #ddd;\n    padding: 1rem;\n    border-radius: 8px;\n  }\n}\n\n@layer utilities {\n  .mt-4 { margin-top: 1rem; }\n  .text-center { text-align: center; }\n}\n\n/* Lower layer loses to higher layer */\n/* If same specificity, layer order decides */', keyPoints: ['@layer defines named layers', 'Layer order determines priority', 'Unlayered styles beat layered', 'Great for third-party CSS'] }),
    c('Subgrid', 'Advanced', 'Inheriting grid tracks from parent grid for aligned nested layouts', { codeExample: '.parent-grid {\n  display: grid;\n  grid-template-columns: 1fr 2fr 1fr;\n  gap: 1rem;\n}\n\n.child-in-grid {\n  display: grid;\n  grid-column: 2 / 3;\n  grid-template-columns: subgrid;\n  /* Child aligns with parent column tracks */\n}\n\n/* Without subgrid, child creates own tracks */\n/* With subgrid, child inherits parent tracks */\n\n.subgrid-row {\n  display: grid;\n  grid-template-rows: subgrid;\n  grid-row: span 3;\n}', keyPoints: ['Inherits parent grid tracks', 'Aligns children with parent columns', 'Works for both columns and rows', 'Prevents nested grid misalignment'] }),
  ]},
]);
// ========== GIT (20 concepts) ==========
course('git', 'Git', 'fab fa-git-alt', '#F05032', [
  { name: 'Version Control', concepts: [
    c('Branching & Merging', 'Intermediate', 'Creating isolated lines of development and combining them back', { codeExample: '# Create and switch\ngit checkout -b feature/new-feature\n\n# Work, commit, then merge\ngit checkout main\ngit merge feature/new-feature\n\n# Rebase for cleaner history\ngit rebase main\n\n# Conflict resolution\ngit merge --abort  # if needed', keyPoints: ['Branches are lightweight pointers', 'merge preserves history', 'rebase rewrites history', 'Conflict resolution is manual'] }),
    c('Git Workflows', 'Beginner', 'Common patterns for organizing work: Git Flow, GitHub Flow, Trunk-based', { keyPoints: ['Git Flow: main, develop, feature, release, hotfix', 'GitHub Flow: main -> feature -> PR', 'Trunk-based: short-lived branches', 'Choose based on release cadence'], followUps: ['Git Flow vs GitHub Flow vs Trunk-based?'] }),
    c('Staging Area & Commits', 'Beginner', 'Working directory, staging area (index), and commit history workflow', { codeExample: '# Working directory -> Staging -> Repository\ngit add file.txt          # stage\ngit add -p file.txt       # stage partially\ngit status                # check\ngit diff --staged         # review staged\ngit commit -m "Message"   # commit\n\n# Amend last commit\ngit commit --amend -m "New message"\n\n# Interactive rebase\ngit rebase -i HEAD~3', keyPoints: ['Three states: modified, staged, committed', 'git add moves to staging', 'git commit creates snapshot', 'git status shows current state'] }),
    c('Remote Repositories', 'Beginner', 'Working with remote repositories: clone, push, pull, fetch', { codeExample: '# Clone a repo\ngit clone https://github.com/user/repo.git\n\n# Remote management\ngit remote -v\ngit remote add upstream https://github.com/other/repo.git\n\n# Push and pull\ngit push origin main\ngit push --tags\ngit pull origin main      # fetch + merge\ngit fetch origin          # fetch without merge\n\n# Set upstream branch\ngit push -u origin feature', keyPoints: ['origin is default remote name', 'pull = fetch + merge', 'fetch only downloads', 'push sends commits to remote'] }),
  ]},
  { name: 'Advanced Git', concepts: [
    c('Rebase & Interactive Rebase', 'Advanced', 'Rewriting commit history by moving, squashing, or editing commits', { codeExample: '# Rebase onto another branch\ngit rebase main\n\n# Interactive rebase\ngit rebase -i HEAD~5\n# Commands:\n# pick - use commit\n# squash - combine with previous\n# reword - change message\n# edit - stop to amend\n# drop - remove commit\n# fixup - squash but discard message\n\n# Golden rule: never rebase public/shared branches\n\n# Conflict resolution during rebase\ngit rebase --continue\ngit rebase --skip\ngit rebase --abort', keyPoints: ['Rebase rewrites history', 'Interactive rebase for cleanup', 'Golden rule: no rebase on shared branches', 'Squash fixup commits before PR'] }),
    c('Cherry-pick & Revert', 'Intermediate', 'Applying specific commits or undoing changes', { codeExample: '# Cherry-pick a commit to current branch\ngit cherry-pick abc1234\n\n# Cherry-pick multiple\ngit cherry-pick abc1234 def5678\n\n# Cherry-pick range\ngit cherry-pick abc1234..def5678\n\n# Revert a commit (creates new commit)\ngit revert abc1234\n\n# Reset (destructive!)\ngit reset --soft HEAD~1     # keep changes staged\ngit reset --mixed HEAD~1    # keep changes unstaged\ngit reset --hard HEAD~1     # discard changes', keyPoints: ['cherry-pick applies commit to current branch', 'revert is safe (new commit)', 'reset is destructive for --hard', 'Use revert for public branches'] }),
    c('Stash & Clean', 'Intermediate', 'Temporarily saving uncommitted changes and cleaning working directory', { codeExample: '# Stash changes\ngit stash\ngit stash push -m "WIP: fixing bug"\ngit stash list\n\n# Apply stash\ngit stash pop              # apply and drop\ngit stash apply stash@{2}  # apply without drop\ngit stash drop stash@{0}   # remove stash\n\n# Partial stash\ngit stash push -p          # interactive\n\n# Clean untracked files\ngit clean -n               # dry run\ngit clean -fd              # force, include dirs\n\n# Create branch from stash\ngit stash branch new-feature', keyPoints: ['stash saves modified tracked files', '-u includes untracked, -a includes ignored', 'pop = apply + drop', 'Use stash for context switching'] }),
    c('Git Hooks', 'Advanced', 'Automated scripts that run on Git events like commit, push, merge', { codeExample: '# .git/hooks/pre-commit\n#!/bin/sh\nnpm run lint\nif [ $? -ne 0 ]; then\n  echo "Linting failed. Commit rejected."\n  exit 1\nfi\n\n# .git/hooks/commit-msg\n#!/bin/sh\n# Enforce conventional commits\nif ! grep -qE "^(feat|fix|docs|chore|refactor|test):" "$1"; then\n  echo "Use conventional commit format"\n  exit 1\nfi\n\n# .git/hooks/pre-push\n#!/bin/sh\nnpm test', keyPoints: ['Client-side hooks (commit, push)', 'Server-side hooks (pre-receive, update)', 'Make hooks executable', 'husky for sharing hooks with team'] }),
  ]},
  { name: 'Collaboration', concepts: [
    c('Pull Requests & Code Review', 'Beginner', 'Proposing changes and reviewing code before merging into main branch', { codeExample: '# Create feature branch\ngit checkout -b feature/amazing\n\n# Make changes, commit, push\ngit push -u origin feature/amazing\n\n# Then create PR on GitHub/GitLab\n# Reviewers leave comments\n# Address feedback with more commits\n\n# Update PR with rebase\ngit rebase main\ngit push --force-with-lease\n\n# Merge options:\n# - Merge commit (preserves history)\n# - Squash merge (clean log)\n# - Rebase merge (linear)', keyPoints: ['PR proposes changes for review', 'Small, focused PRs review better', 'Address feedback constructively', 'Choose merge strategy for team'] }),
    c('Conflict Resolution', 'Intermediate', 'Resolving merge conflicts when Git cannot automatically merge changes', { codeExample: '# When conflict occurs:\n# 1. Git marks conflicted files\ngit status\n\n# 2. Open file and look for markers:\n# <<<<<<< HEAD\n# your changes\n# =======\n# their changes\n# >>>>>>> feature-branch\n\n# 3. Edit to resolve, remove markers\n\n# 4. Mark as resolved\ngit add resolved-file.txt\n\n# 5. Complete the merge\ngit commit\n\n# Tools\ngit mergetool   # visual tool\ngit diff        # see differences', keyPoints: ['Conflict markers show both versions', 'Resolve manually, keep desired code', 'git mergetool for visual resolution', 'Prevent with frequent pulls'] }),
    c('Tagging & Releases', 'Beginner', 'Marking specific commits as releases with annotated or lightweight tags', { codeExample: '# Lightweight tag\ngit tag v1.0.0\n\n# Annotated tag (recommended for releases)\ngit tag -a v1.0.0 -m "Release version 1.0.0"\n\n# List tags\ngit tag -l "v1.*"\n\n# Push tags\ngit push origin v1.0.0\ngit push --tags  # all tags\n\n# Checkout tag\ngit checkout v1.0.0\n\n# Signed tag\ngit tag -s v1.0.0 -m "Signed release"\n\n# Delete tag\ngit tag -d v1.0.0\ngit push origin :refs/tags/v1.0.0', keyPoints: ['Annotated for releases (author, date, message)', 'Semantic versioning (major.minor.patch)', 'Tags are not automatically pushed', 'Signed tags verify authenticity'] }),
  ]},
]);

// ========== DOCKER (20 concepts) ==========
course('docker', 'Docker', 'fab fa-docker', '#2496ED', [
  { name: 'Containerization', concepts: [
    c('Dockerfile & Images', 'Intermediate', 'Blueprint for building Docker images with layered filesystem', { codeExample: 'FROM node:18-alpine\nWORKDIR /app\nCOPY package*.json ./\nRUN npm ci --only=production\nCOPY . .\nEXPOSE 3000\nCMD ["node", "server.js"]', keyPoints: ['Multi-stage builds for smaller images', 'Layer caching optimization', '.dockerignore to exclude files', 'Distroless images for security'] }),
    c('Docker Compose', 'Intermediate', 'Define and run multi-container applications with a single YAML file', { codeExample: 'version: "3.8"\nservices:\n  web:\n    build: .\n    ports:\n      - "3000:3000"\n    depends_on:\n      - db\n    environment:\n      - NODE_ENV=production\n  db:\n    image: postgres:15\n    volumes:\n      - pgdata:/var/lib/postgresql/data\n    environment:\n      POSTGRES_PASSWORD: secret\nvolumes:\n  pgdata:', keyPoints: ['Service definitions', 'Networking between containers', 'Volumes for persistent data', 'depends_on for startup ordering'] }),
    c('Container Lifecycle', 'Beginner', 'Creating, starting, stopping, and removing containers', { codeExample: '# Run a container\ndocker run -d --name myapp -p 8080:80 nginx:alpine\n\n# List containers\ndocker ps              # running\ndocker ps -a           # all\n\n# Control\ndocker stop myapp\ndocker start myapp\ndocker restart myapp\ndocker pause myapp\ndocker unpause myapp\n\n# Execute command in running container\ndocker exec -it myapp sh\n\n# Inspect\ndocker logs myapp\ndocker inspect myapp\ndocker stats\n\n# Remove\ndocker rm myapp\ndocker container prune  # all stopped', keyPoints: ['run = pull + create + start', '-d for detached, -it for interactive', 'docker exec for commands', 'docker logs for output'] }),
    c('Volumes & Data Persistence', 'Intermediate', 'Persisting container data with volumes, bind mounts, and tmpfs mounts', { codeExample: '# Named volume\ndocker volume create mydata\ndocker run -v mydata:/app/data myapp\n\n# Bind mount (host directory)\ndocker run -v /host/path:/container/path myapp\n\n# Read-only bind mount\ndocker run -v /host/data:/app/data:ro myapp\n\n# tmpfs (in-memory, for secrets)\ndocker run --tmpfs /app/temp myapp\n\n# Volume backup\ndocker run --rm -v mydata:/source -v /backup:/dest alpine \\\n  tar czf /dest/backup.tar.gz -C /source .', keyPoints: ['Volumes managed by Docker', 'Bind mounts map host paths', 'tmpfs is in-memory (fast, secure)', 'Volume drivers for cloud storage'] }),
  ]},
  { name: 'Networking', concepts: [
    c('Docker Networks', 'Intermediate', 'Communication between containers using bridge, host, overlay networks', { codeExample: '# Network types\ndocker network create --driver bridge mynet\n\n# Run containers on network\ndocker run --network mynet --name app1 myapp\ndocker run --network mynet --name app2 myapp\n\n# Container communication by name\n# app1 can ping app2 by container name\n\n# Host network (container shares host network)\ndocker run --network host myapp\n\n# Expose ports\ndocker run -p 8080:80 nginx           # host:container\ndocker run -p 127.0.0.1:8080:80 nginx # bind to IP', keyPoints: ['Bridge: default, isolated', 'Host: shares host network', 'Overlay: multi-host (Swarm)', 'Containers on same bridge communicate'] }),
    c('Docker Registry & Hub', 'Beginner', 'Storing and distributing container images via registries', { codeExample: '# Login to Docker Hub\ndocker login\n\n# Pull image\ndocker pull nginx:alpine\n\n# Tag and push\ndocker tag myapp:latest username/myapp:latest\ndocker push username/myapp:latest\n\n# Private registry\ndocker run -d -p 5000:5000 --name registry registry:2\ndocker tag myapp localhost:5000/myapp\ndocker push localhost:5000/myapp\n\n# Image tags\ndocker pull ubuntu:22.04\ndocker pull node:18-slim\ndocker pull python:3.11-alpine', keyPoints: ['Docker Hub is default public registry', 'Tag format: user/repo:tag', 'Private registries for team images', 'Pull policy: always/never/if-not-present'] }),
  ]},
  { name: 'Orchestration & Production', concepts: [
    c('Dockerfile Best Practices', 'Intermediate', 'Optimizing Dockerfiles for security, size, and build speed', { codeExample: '# 1. Use specific base image tags\nFROM node:18-alpine AS builder\n\n# 2. Order layers by change frequency\nCOPY package*.json ./\nRUN npm ci\nCOPY . .\n\n# 3. Multi-stage builds\nFROM node:18-alpine\nCOPY --from=builder /app/dist ./dist\nCOPY --from=builder /app/node_modules ./node_modules\n\n# 4. Non-root user\nRUN addgroup -S appgroup && adduser -S appuser -G appgroup\nUSER appuser\n\n# 5. Health check\nHEALTHCHECK --interval=30s --timeout=3s \\\n  CMD wget --no-verbose --tries=1 http://localhost:3000/health || exit 1\n\n# 6. Metadata\nLABEL maintainer="team@example.com" version="1.0.0"', keyPoints: ['Minimize layers', 'Leverage cache with correct order', 'Multi-stage for small images', 'Non-root user for security'] }),
    c('Docker Swarm & Kubernetes', 'Advanced', 'Container orchestration for managing clusters of Docker hosts', { codeExample: '# Docker Swarm\ndocker swarm init\ndocker service create --replicas 3 --name web -p 80:80 nginx\ndocker service scale web=5\ndocker service update --image nginx:alpine web\n\n# Kubernetes (k8s) basics:\n# kubectl run web --image=nginx --replicas=3\n# kubectl expose deployment web --port=80 --type=LoadBalancer\n\n# Key concepts:\n# - Pod: smallest deployable unit\n# - Service: stable network endpoint\n# - Deployment: declarative updates\n# - ConfigMap/Secret: configuration', keyPoints: ['Swarm: Docker-native, simpler', 'K8s: industry standard, complex', 'Swarm: service abstraction', 'K8s: pod, deployment, service'] }),
    c('Docker Security', 'Advanced', 'Best practices for securing containerized applications', { codeExample: '# Security scan\ndocker scan myapp\n\n# Run with limited capabilities\ndocker run --cap-drop ALL --cap-add NET_BIND_SERVICE myapp\n\n# Read-only root filesystem\ndocker run --read-only --tmpfs /tmp myapp\n\n# Resource limits\ndocker run --memory="512m" --cpus="2" myapp\n\n# Security options\ndocker run --security-opt=no-new-privileges:true \\\n           --security-opt=seccomp=profile.json myapp\n\n# Don\'t run as root (USER directive in Dockerfile)\n# Use secrets, not env vars for sensitive data\n# ---secrets flag for Docker Swarm', keyPoints: ['Scan images for vulnerabilities', 'Drop all capabilities, add only needed', 'Read-only root filesystem', 'Resource limits prevent DoS'] }),
  ]},
]);
// ========== DSA (35 concepts) ==========
course('dsa', 'DSA', 'fas fa-sitemap', '#6C5CE7', [
  { name: 'Data Structures', concepts: [
    c('Arrays & Hashing', 'Intermediate', 'Fundamental data structures for storing and accessing data', { codeExample: '// Two Sum - O(n) using HashMap\nfunction twoSum(nums, target) {\n  const map = new Map();\n  for (let i = 0; i < nums.length; i++) {\n    const complement = target - nums[i];\n    if (map.has(complement)) {\n      return [map.get(complement), i];\n    }\n    map.set(nums[i], i);\n  }\n  return [];\n}', keyPoints: ['Array: O(1) access, O(n) insertion', 'HashMap: O(1) average get/put', 'Space vs time trade-off'] }),
    c('Linked Lists', 'Intermediate', 'Linear data structure of nodes connected by pointers', { codeExample: 'class ListNode {\n  constructor(val) {\n    this.val = val;\n    this.next = null;\n  }\n}\n\n// Reverse linked list\nfunction reverseList(head) {\n  let prev = null;\n  let curr = head;\n  while (curr) {\n    const next = curr.next;\n    curr.next = prev;\n    prev = curr;\n    curr = next;\n  }\n  return prev;\n}', keyPoints: ['Singly vs doubly linked', 'O(n) access, O(1) insertion at known position', 'Two-pointer technique for cycles'] }),
    c('Stacks & Queues', 'Intermediate', 'LIFO (Stack) and FIFO (Queue) data structures', { codeExample: '// Stack using array\nclass Stack {\n  constructor() { this.items = []; }\n  push(x) { this.items.push(x); }\n  pop() { return this.items.pop(); }\n  peek() { return this.items[this.items.length - 1]; }\n  isEmpty() { return this.items.length === 0; }\n}\n\n// Queue - valid parentheses\nfunction isValid(s) {\n  const stack = [];\n  const map = { ")": "(", "}": "{", "]": "[" };\n  for (const c of s) {\n    if (c in map) {\n      if (stack.pop() !== map[c]) return false;\n    } else {\n      stack.push(c);\n    }\n  }\n  return stack.length === 0;\n}', keyPoints: ['Stack: DFS, undo, expression evaluation', 'Queue: BFS, task scheduling', 'Deque for double-ended ops'] }),
    c('Trees & Graphs', 'Advanced', 'Hierarchical data structures with nodes and edges', { codeExample: 'class TreeNode {\n  constructor(val) {\n    this.val = val;\n    this.left = null;\n    this.right = null;\n  }\n}\n\n// BFS\nfunction bfs(root) {\n  const queue = [root];\n  while (queue.length) {\n    const node = queue.shift();\n    console.log(node.val);\n    if (node.left) queue.push(node.left);\n    if (node.right) queue.push(node.right);\n  }\n}\n\n// DFS (inorder)\nfunction inorder(root) {\n  if (!root) return;\n  inorder(root.left);\n  console.log(root.val);\n  inorder(root.right);\n}', keyPoints: ['BFS uses queue, DFS uses stack/recursion', 'Tree: no cycles, Graph: can have cycles', 'BST: O(log n) average'] }),
    c('Heaps & Priority Queues', 'Intermediate', 'Complete binary tree where parent is always greater/smaller than children', { codeExample: 'class MinHeap {\n  constructor() { this.heap = []; }\n\n  push(val) {\n    this.heap.push(val);\n    this._bubbleUp(this.heap.length - 1);\n  }\n\n  pop() {\n    const top = this.heap[0];\n    const last = this.heap.pop();\n    if (this.heap.length > 0) {\n      this.heap[0] = last;\n      this._sinkDown(0);\n    }\n    return top;\n  }\n\n  _bubbleUp(i) {\n    while (i > 0) {\n      const parent = Math.floor((i-1)/2);\n      if (this.heap[i] >= this.heap[parent]) break;\n      [this.heap[i], this.heap[parent]] = [this.heap[parent], this.heap[i]];\n      i = parent;\n    }\n  }\n\n  _sinkDown(i) {\n    while (true) {\n      let smallest = i;\n      const left = 2*i+1, right = 2*i+2;\n      if (left < this.heap.length && this.heap[left] < this.heap[smallest]) smallest = left;\n      if (right < this.heap.length && this.heap[right] < this.heap[smallest]) smallest = right;\n      if (smallest === i) break;\n      [this.heap[i], this.heap[smallest]] = [this.heap[smallest], this.heap[i]];\n      i = smallest;\n    }\n  }\n}', keyPoints: ['Min-heap: smallest at top', 'Max-heap: largest at top', 'Insert/delete O(log n)', 'Used in Dijkstra, Huffman'] }),
    c('Tries', 'Advanced', 'Tree-like data structure for efficient string prefix search and storage', { codeExample: 'class TrieNode {\n  constructor() {\n    this.children = {};\n    this.isEnd = false;\n  }\n}\n\nclass Trie {\n  constructor() { this.root = new TrieNode(); }\n\n  insert(word) {\n    let node = this.root;\n    for (const c of word) {\n      if (!node.children[c]) node.children[c] = new TrieNode();\n      node = node.children[c];\n    }\n    node.isEnd = true;\n  }\n\n  search(word) {\n    let node = this.root;\n    for (const c of word) {\n      if (!node.children[c]) return false;\n      node = node.children[c];\n    }\n    return node.isEnd;\n  }\n\n  startsWith(prefix) {\n    let node = this.root;\n    for (const c of prefix) {\n      if (!node.children[c]) return false;\n      node = node.children[c];\n    }\n    return true;\n  }\n}', keyPoints: ['O(L) insert/search for word of length L', 'Prefix matching (autocomplete)', 'Memory intensive but fast'] }),
  ]},
  { name: 'Algorithms', concepts: [
    c('Sorting Algorithms', 'Intermediate', 'Various algorithms for ordering elements: QuickSort, MergeSort, HeapSort', { codeExample: '// QuickSort\nfunction quickSort(arr, low = 0, high = arr.length - 1) {\n  if (low < high) {\n    const pi = partition(arr, low, high);\n    quickSort(arr, low, pi - 1);\n    quickSort(arr, pi + 1, high);\n  }\n  return arr;\n}\n\nfunction partition(arr, low, high) {\n  const pivot = arr[high];\n  let i = low - 1;\n  for (let j = low; j < high; j++) {\n    if (arr[j] < pivot) {\n      i++;\n      [arr[i], arr[j]] = [arr[j], arr[i]];\n    }\n  }\n  [arr[i+1], arr[high]] = [arr[high], arr[i+1]];\n  return i + 1;\n}\n\n// MergeSort\nfunction mergeSort(arr) {\n  if (arr.length <= 1) return arr;\n  const mid = Math.floor(arr.length / 2);\n  const left = mergeSort(arr.slice(0, mid));\n  const right = mergeSort(arr.slice(mid));\n  return merge(left, right);\n}', keyPoints: ['QuickSort: O(n log n) avg, O(n^2) worst', 'MergeSort: O(n log n), stable', 'HeapSort: O(n log n), in-place'] }),
    c('Binary Search', 'Beginner', 'Efficiently finding elements in a sorted array in O(log n) time', { codeExample: 'function binarySearch(arr, target) {\n  let left = 0, right = arr.length - 1;\n\n  while (left <= right) {\n    const mid = Math.floor((left + right) / 2);\n    if (arr[mid] === target) return mid;\n    if (arr[mid] < target) left = mid + 1;\n    else right = mid - 1;\n  }\n  return -1;\n}\n\n// Lower bound (first >= target)\nfunction lowerBound(arr, target) {\n  let left = 0, right = arr.length;\n  while (left < right) {\n    const mid = Math.floor((left + right) / 2);\n    if (arr[mid] < target) left = mid + 1;\n    else right = mid;\n  }\n  return left;\n}', keyPoints: ['Requires sorted array', 'O(log n) time', 'Variants: lower/upper bound, rotated search'] }),
    c('Two Pointers & Sliding Window', 'Intermediate', 'Efficient array traversal patterns for subarray/substring problems', { codeExample: '// Two Sum II (sorted array)\nfunction twoSumSorted(nums, target) {\n  let left = 0, right = nums.length - 1;\n  while (left < right) {\n    const sum = nums[left] + nums[right];\n    if (sum === target) return [left + 1, right + 1];\n    if (sum < target) left++;\n    else right--;\n  }\n  return [];\n}\n\n// Sliding window - max sum subarray of size k\nfunction maxSumSubarray(arr, k) {\n  let sum = 0, maxSum = 0;\n  for (let i = 0; i < k; i++) sum += arr[i];\n  maxSum = sum;\n  for (let i = k; i < arr.length; i++) {\n    sum += arr[i] - arr[i - k];\n    maxSum = Math.max(maxSum, sum);\n  }\n  return maxSum;\n}', keyPoints: ['Two pointers for sorted arrays', 'Sliding window for subarrays', 'O(n) time, O(1) space'] }),
    c('Dynamic Programming', 'Advanced', 'Breaking problems into overlapping subproblems and storing results', { codeExample: '// Fibonacci with memoization\nfunction fib(n, memo = {}) {\n  if (n <= 1) return n;\n  if (memo[n] !== undefined) return memo[n];\n  memo[n] = fib(n-1, memo) + fib(n-2, memo);\n  return memo[n];\n}\n\n// Bottom-up DP\nfunction fibTab(n) {\n  const dp = [0, 1];\n  for (let i = 2; i <= n; i++) {\n    dp[i] = dp[i-1] + dp[i-2];\n  }\n  return dp[n];\n}\n\n// 0/1 Knapsack\nfunction knapSack(W, wt, val, n) {\n  const dp = Array.from({length: n+1}, () => Array(W+1).fill(0));\n  for (let i = 1; i <= n; i++) {\n    for (let w = 1; w <= W; w++) {\n      if (wt[i-1] <= w) {\n        dp[i][w] = Math.max(val[i-1] + dp[i-1][w-wt[i-1]], dp[i-1][w]);\n      } else {\n        dp[i][w] = dp[i-1][w];\n      }\n    }\n  }\n  return dp[n][W];\n}', keyPoints: ['Optimal substructure + overlapping subproblems', 'Top-down (memo) vs Bottom-up (tabulation)', 'Common patterns: knapsack, LCS, subset sum'] }),
    c('Graph Algorithms', 'Advanced', 'BFS, DFS, Dijkstra, topological sort, MST, union-find', { codeExample: '// Dijkstra algorithm\nfunction dijkstra(graph, start) {\n  const distances = {};\n  const visited = {};\n  const pq = [[0, start]];\n\n  for (const node in graph) distances[node] = Infinity;\n  distances[start] = 0;\n\n  while (pq.length) {\n    pq.sort((a, b) => a[0] - b[0]);\n    const [dist, node] = pq.shift();\n    if (visited[node]) continue;\n    visited[node] = true;\n\n    for (const [neighbor, weight] of graph[node]) {\n      const newDist = dist + weight;\n      if (newDist < distances[neighbor]) {\n        distances[neighbor] = newDist;\n        pq.push([newDist, neighbor]);\n      }\n    }\n  }\n  return distances;\n}\n\n// Union-Find (Disjoint Set)\nclass UnionFind {\n  constructor(n) {\n    this.parent = Array.from({length: n}, (_, i) => i);\n    this.rank = Array(n).fill(0);\n  }\n\n  find(x) {\n    if (this.parent[x] !== x) this.parent[x] = this.find(this.parent[x]);\n    return this.parent[x];\n  }\n\n  union(x, y) {\n    const px = this.find(x), py = this.find(y);\n    if (px === py) return false;\n    if (this.rank[px] < this.rank[py]) { this.parent[px] = py; }\n    else if (this.rank[px] > this.rank[py]) { this.parent[py] = px; }\n    else { this.parent[py] = px; this.rank[px]++; }\n    return true;\n  }\n}', keyPoints: ['BFS for shortest path (unweighted)', 'Dijkstra for weighted graphs', 'Union-Find for connectivity', 'Topological sort for DAGs'] }),
  ]},
  { name: 'Complexity Analysis', concepts: [
    c('Big O Notation', 'Beginner', 'Mathematical notation describing the limiting behavior of algorithm runtime/space', { keyPoints: ['O(1): constant (array access)', 'O(log n): logarithmic (binary search)', 'O(n): linear (single loop)', 'O(n log n): linearithmic (sorting)', 'O(n^2): quadratic (nested loops)', 'O(2^n): exponential (subset generation)'] }),
    c('Time Complexity Analysis', 'Intermediate', 'Determining how runtime grows with input size for algorithm comparison', { codeExample: '// O(1) - constant\nfunction getFirst(arr) { return arr[0]; }\n\n// O(n) - linear\nfunction findMax(arr) {\n  let max = arr[0];\n  for (const x of arr) if (x > max) max = x;\n  return max;\n}\n\n// O(n^2) - quadratic\nfunction bubbleSort(arr) {\n  for (let i = 0; i < arr.length; i++) {\n    for (let j = 0; j < arr.length - i - 1; j++) {\n      if (arr[j] > arr[j+1]) [arr[j], arr[j+1]] = [arr[j+1], arr[j]];\n    }\n  }\n  return arr;\n}', keyPoints: ['Drop constants (O(2n) = O(n))', 'Drop lower order terms', 'Worst-case analysis standard', 'Amortized analysis for data structures'] }),
    c('Space Complexity', 'Intermediate', 'Analyzing memory usage of an algorithm relative to input size', { codeExample: '// O(1) space - in-place\nfunction reverse(arr) {\n  let i = 0, j = arr.length - 1;\n  while (i < j) {\n    [arr[i], arr[j]] = [arr[j], arr[i]];\n    i++; j--;\n  }\n  return arr;\n}\n\n// O(n) space - auxiliary array\nfunction merge(left, right) {\n  const result = [];\n  let i = 0, j = 0;\n  while (i < left.length && j < right.length) {\n    result.push(left[i] < right[j] ? left[i++] : right[j++]);\n  }\n  return result.concat(left.slice(i)).concat(right.slice(j));\n}', keyPoints: ['Input space vs auxiliary space', 'Recursion uses call stack space', 'Time-space trade-off'] }),
  ]},
  { name: 'Problem Solving Strategies', concepts: [
    c('Recursion & Backtracking', 'Intermediate', 'Solving problems by trying partial solutions and abandoning if not viable', { codeExample: '// N-Queens\nfunction solveNQueens(n) {\n  const result = [];\n  const board = Array.from({length: n}, () => Array(n).fill("."));\n\n  function isSafe(row, col) {\n    for (let i = 0; i < row; i++) {\n      if (board[i][col] === "Q") return false;\n      const diff = row - i;\n      if ((col - diff >= 0 && board[i][col - diff] === "Q") ||\n          (col + diff < n && board[i][col + diff] === "Q")) return false;\n    }\n    return true;\n  }\n\n  function backtrack(row) {\n    if (row === n) {\n      result.push(board.map(r => r.join("")));\n      return;\n    }\n    for (let col = 0; col < n; col++) {\n      if (isSafe(row, col)) {\n        board[row][col] = "Q";\n        backtrack(row + 1);\n        board[row][col] = ".";\n      }\n    }\n  }\n\n  backtrack(0);\n  return result;\n}', keyPoints: ['Backtracking explores all candidates', 'Pruning eliminates dead ends', 'Used for permutations, subsets, N-Queens'] }),
    c('Greedy Algorithms', 'Intermediate', 'Making locally optimal choices to find global optimum', { codeExample: '// Activity Selection\nfunction activitySelection(start, end) {\n  const activities = start.map((s, i) => ({ start: s, end: end[i], index: i }));\n  activities.sort((a, b) => a.end - b.end);\n\n  const selected = [activities[0]];\n  let lastEnd = activities[0].end;\n\n  for (let i = 1; i < activities.length; i++) {\n    if (activities[i].start >= lastEnd) {\n      selected.push(activities[i]);\n      lastEnd = activities[i].end;\n    }\n  }\n  return selected.map(a => a.index);\n}\n\n// Coin Change (greedy works for standard denominations)\nfunction minCoins(coins, amount) {\n  coins.sort((a, b) => b - a);\n  let count = 0;\n  for (const coin of coins) {\n    while (amount >= coin) {\n      amount -= coin;\n      count++;\n    }\n  }\n  return amount === 0 ? count : -1;\n}', keyPoints: ['Local optimum leads to global optimum', 'Sorting often required', 'Not always optimal (counterexamples exist)'] }),
    c('Divide & Conquer', 'Intermediate', 'Breaking problem into subproblems, solving recursively, combining results', { codeExample: '// Merge Sort\nfunction mergeSort(arr) {\n  if (arr.length <= 1) return arr;\n  const mid = Math.floor(arr.length / 2);\n  const left = mergeSort(arr.slice(0, mid));\n  const right = mergeSort(arr.slice(mid));\n  return merge(left, right);\n}\n\nfunction merge(left, right) {\n  const result = [];\n  let i = 0, j = 0;\n  while (i < left.length && j < right.length) {\n    result.push(left[i] < right[j] ? left[i++] : right[j++]);\n  }\n  return result.concat(left.slice(i)).concat(right.slice(j));\n}\n\n// Maximum subarray (Kadane variant)\nfunction maxSubarray(arr) {\n  let maxSoFar = arr[0], maxEndingHere = arr[0];\n  for (let i = 1; i < arr.length; i++) {\n    maxEndingHere = Math.max(arr[i], maxEndingHere + arr[i]);\n    maxSoFar = Math.max(maxSoFar, maxEndingHere);\n  }\n  return maxSoFar;\n}', keyPoints: ['Divide, conquer (recurse), combine', 'MergeSort, QuickSort, Binary Search', 'Often O(n log n) time'] }),
  ]},
]);

